bool Assets::InitializePartition() {
    // Reset previous state
    partition_valid_ = false;
    checksum_valid_ = false;
    assets_.clear();

    // Find the assets partition
    partition_ = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA,
        ESP_PARTITION_SUBTYPE_ANY,
        "assets"
    );

    if (!partition_) {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Map the entire partition into memory
    const void* mapped_ptr;
    esp_err_t err = esp_partition_mmap(
        partition_,
        0,
        partition_->size,
        SPI_FLASH_MMAP_DATA,
        &mapped_ptr,
        &mmap_handle_
    );

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    mmap_root_ = static_cast<const char*>(mapped_ptr);

    // Assume first part contains number of entries followed by table
    const uint32_t* num_entries_ptr = reinterpret_cast<const uint32_t*>(mmap_root_);
    uint32_t num_entries = *num_entries_ptr;

    if (num_entries == 0 || num_entries > 1024) { // sanity check
        ESP_LOGE(TAG, "Invalid number of assets in partition: %" PRIu32, num_entries);
        return false;
    }

    const mmap_assets_table* table_start =
        reinterpret_cast<const mmap_assets_table*>(mmap_root_ + sizeof(uint32_t));

    // Build asset index
    for (uint32_t i = 0; i < num_entries; ++i) {
        const auto& entry = table_start[i];
        std::string name(entry.asset_name);

        Asset asset{};
        asset.size = entry.asset_size;
        asset.offset = entry.asset_offset;

        assets_[name] = asset;
    }

    // Checksum validation: calculate checksum starting after the table
    const char* data_start = mmap_root_ + sizeof(uint32_t) + num_entries * sizeof(mmap_assets_table);
    uint32_t data_length = partition_->size - (data_start - mmap_root_);

    uint32_t stored_checksum = *reinterpret_cast<const uint32_t*>(data_start - sizeof(uint32_t));
    uint32_t calculated_checksum = CalculateChecksum(data_start, data_length);

    checksum_valid_ = (stored_checksum == calculated_checksum);
    if (!checksum_valid_) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%" PRIX32 ", calculated=0x%" PRIX32,
                 stored_checksum, calculated_checksum);
        return false;
    }

    partition_valid_ = true;
    ESP_LOGI(TAG, "Assets partition initialized successfully with %d assets", num_entries);
    return true;
}

