bool Assets::Apply()
{
    if (!partition_valid_) {
        ESP_LOGE(TAG, "Asset partition is not valid");
        return false;
    }

    if (mmap_root_ == nullptr) {
        ESP_LOGE(TAG, "Memory mapping not initialized");
        return false;
    }

    // Get the index.json asset data
    void* index_data = nullptr;
    size_t index_size = 0;

    if (!GetAssetData("index.json", index_data, index_size)) {
        ESP_LOGE(TAG, "Failed to get index.json asset data");
        return false;
    }

    // Parse the JSON
    cJSON* root = cJSON_ParseWithLength((const char*)index_data, index_size);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return false;
    }

    bool success = true;

    // Check asset version
    cJSON* version = cJSON_GetObjectItem(root, "version");
    if (version && cJSON_IsString(version)) {
        ESP_LOGI(TAG, "Applying assets version: %s", version->valuestring);
    } else {
        ESP_LOGW(TAG, "No version found in index.json");
    }

    // Load speech recognition models
    cJSON* models = cJSON_GetObjectItem(root, "models");
