bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    if (!partition_) {
        ESP_LOGE(TAG, "Partition not initialized");
        return false;
    }

    // Initialize HTTP client
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.timeout_ms = 10000;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Open HTTP connection
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length: %d", content_length);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Validate content size against partition size
    if ((size_t)content_length > partition_->size) {
        ESP_LOGE(TAG, "Content size (%d) exceeds partition size (%d)", content_length, partition_->size);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase partition before writing
    err = esp_partition_erase_range(partition_, 0, partition_->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Download and write data
    const size_t BUFFER_SIZE = 4096;
    uint8_t* buffer = (uint8_t*)malloc(BUFFER_SIZE);
    if (!buffer) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    size_t total_written = 0;
    size_t offset = 0;
    int last_progress = -1;
    int64_t start_time = esp_timer_get_time();
    size_t last_reported_bytes = 0;
    int64_t last_report_time = start_time;

    while (total_written < (size_t)content_length) {
        int data_read = esp_http_client_read(client, (char*)buffer, BUFFER_SIZE);
        if (data_read < 0) {
            ESP_LOGE(TAG, "HTTP read error");
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        if (data_read == 0) {
            // No more data
            break;
        }

        // Write to flash
        err = esp_partition_write(partition_, offset, buffer, data_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to partition: %s", esp_err_to_name(err));
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        total_written += data_read;
        offset += data_read;

        // Calculate progress and speed
        int current_progress = (total_written * 100) / content_length;
        int64_t current_time = esp_timer_get_time();
        size_t bytes_since_last_report = total_written - last_reported_bytes;
        int64_t time_since_last_report = current_time - last_report_time;

        size_t current_speed = 0;
        if (time_since_last_report > 0) {
            current_speed = (bytes_since_last_report * 1000000) / time_since_last_report;
        }

        // Report progress if changed
        if (current_progress != last_progress && progress_callback) {
            progress_callback(current_progress, current_speed);
            last_progress = current_progress;
            last_reported_bytes = total_written;
            last_report_time = current_time;
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    // Verify we downloaded all expected data
    if (total_written != (size_t)content_length) {
        ESP_LOGE(TAG, "Incomplete download: expected %d, got %d bytes", content_length, total_written);
        return false;
    }

    ESP_LOGI(TAG, "Download completed successfully: %d bytes", total_written);
    return true;
}

