bool Assets::GetAssetData(const std::string& name, void*& ptr, size_t& size)
{
    // Define assumed magic number here since not found in codebase
    constexpr uint32_t kExpectedMagic = 0x12345678;

    auto it = assets_.find(name);
    if (it == assets_.end()) {
        ESP_LOGE(TAG, "Asset '%s' not found", name.c_str());
        return false;
    }

    const Asset& asset = it->second;
    const char* asset_start = mmap_root_ + asset.offset;

    // Ensure we have enough space for at least the magic number
    if (asset.size < sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Asset '%s' too small to contain header", name.c_str());
        return false;
    }

    // Read magic number (assumed first 4 bytes)
    uint32_t magic = *reinterpret_cast<const uint32_t*>(asset_start);

    if (magic != kExpectedMagic) {
        ESP_LOGE(TAG, "Invalid magic number for asset '%s'", name.c_str());
        return false;
    }

    // Skip header (magic only for now), adjust ptr and size accordingly
    constexpr size_t header_size = sizeof(uint32_t);
    ptr = const_cast<char*>(asset_start) + header_size;
    size = asset.size - header_size;

    return true;
}

