bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    // Self-transitions are always valid
    if (from == to) {
        return true;
    }

    // Define valid transitions based on state flow logic
    switch (from) {
        case kDeviceStateUnknown:
            // From unknown state, only starting is valid
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            // After starting, move to WiFi configuration
            return to == kDeviceStateWifiConfiguring;

        case kDeviceStateWifiConfiguring:
            // After WiFi setup, go to idle or fatal error
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateIdle:
            // From idle, can go to connecting, listening, upgrading, activating, audio testing, or fatal error
            return to == kDeviceStateConnecting || 
                   to == kDeviceStateListening || 
                   to == kDeviceStateUpgrading || 
                   to == kDeviceStateActivating || 
                   to == kDeviceStateAudioTesting || 
                   to == kDeviceStateFatalError;

        case kDeviceStateConnecting:
            // After connecting, return to idle or fatal error
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateListening:
            // While listening, can start speaking, go idle, upgrade, activate, test audio, or fatal error
            return to == kDeviceStateSpeaking || 
                   to == kDeviceStateIdle || 
                   to == kDeviceStateUpgrading || 
                   to == kDeviceStateActivating || 
                   to == kDeviceStateAudioTesting || 
                   to == kDeviceStateFatalError;

        case kDeviceStateSpeaking:
            // After speaking, return to idle or fatal error
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateUpgrading:
            // After upgrading, typically restart or go to fatal error
            return to == kDeviceStateStarting || to == kDeviceStateFatalError;

        case kDeviceStateActivating:
            // After activation, go to idle or fatal error
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateAudioTesting:
            // After audio testing, return to idle or fatal error
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateFatalError:
            // From fatal error, can only restart or stay in error
            return to == kDeviceStateStarting;

        default:
            // Invalid state
            return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState new_state)
{
    std::lock_guard<std::mutex> lock(mutex_);

    DeviceState old_state = current_state_.load();

    // Check if the transition is valid
    if (!IsValidTransition(old_state, new_state)) {
        ESP_LOGW(TAG, "Invalid state transition from %s to %s", 
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Perform the transition
    current_state_.store(new_state);

    ESP_LOGI(TAG, "State transitioned from %s to %s", 
             GetStateName(old_state), GetStateName(new_state));

    // Notify all registered listeners
    NotifyStateChange(old_state, new_state);

    return true;
}

int DeviceStateMachine::AddStateChangeListener(StateCallback callback)
{
    std::lock_guard<std::mutex> lock(mutex_);
    int listener_id = next_listener_id_++;
    listeners_.emplace_back(listener_id, std::move(callback));
    return listener_id;
}

