void DeviceStateMachine::NotifyStateChange(DeviceState old_state, DeviceState new_state)
{
    ESP_LOGD(TAG, "State changed from %s to %s",
             GetStateName(old_state),
             GetStateName(new_state));

    // Copy the list of listeners under lock to ensure thread safety
    std::vector<std::function<void(DeviceState, DeviceState)>> listeners_copy;
    {
        std::lock_guard<std::mutex> lock(listeners_mutex_);
        listeners_copy = listeners_;
    }

    // Invoke all the callbacks with the old and new states
    for (const auto& listener : listeners_copy) {
        if (listener) {
            listener(old_state, new_state);
        }
    }
}

