std::unique_ptr<Http> Ota::SetupHttp()
{
    auto http = std::make_unique<Http>();

    // Set User-Agent header
    std::string userAgent = "XiaozhiDevice/" + current_version_;
    http->setUserAgent(userAgent);

    // Set Content-Type to application/json
    http->setHeader("Content-Type", "application/json");

    // Add device identification
    std::string deviceId = SystemInfo::getDeviceId();
    http->setHeader("X-Device-ID", deviceId);

    // Add language preference
    std::string language = Settings::getLanguage();
    http->setHeader("Accept-Language", language);

    // Conditionally add serial number if device is provisioned
    if (SystemInfo::isProvisioned()) {
        std::string serialNumber = SystemInfo::getSerialNumber();
        http->setHeader("X-Serial-Number", serialNumber);
    }

    return http;
}

