esp_err_t Ota::CheckVersion()
{
    // Reset flags
    has_new_version_ = false;
    has_mqtt_config_ = false;
    has_websocket_config_ = false;
    has_activation_code_ = false;
    has_server_time_ = false;
    has_activation_challenge_ = false;
    has_serial_number_ = false;

    // Get current version
    current_version_ = SystemInfo::GetFirmwareVersion();

    // Setup HTTP client
    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    // Get check version URL
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "Empty check version URL");
        return ESP_FAIL;
    }

    // Add headers
    http->SetHeader("Content-Type", "application/json");
    http->SetHeader("User-Agent", "ESP32-OTA-Client");

    // Send GET request
    std::string response;
    int status_code = http->Get(url, response);

    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP request failed with status code: %d", status_code);
        return ESP_FAIL;
    }

    if (response.empty()) {
        ESP_LOGE(TAG, "Empty response from server");
        return ESP_FAIL;
    }

    // Parse JSON response
    cJSON* json = cJSON_Parse(response.c_str());
    if (!json) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Extract firmware version
    cJSON* version_item = cJSON_GetObjectItem(json, "version");
    if (version_item && cJSON_IsString(version_item)) {
        firmware_version_ = version_item->valuestring;

        // Check if new version is available
        if (!firmware_version_.empty() && IsNewVersionAvailable(current_version_, firmware_version_)) {
            has_new_version_ = true;

            // Extract firmware URL
            cJSON* url_item = cJSON_GetObjectItem(json, "url");
            if (url_item && cJSON_IsString(url_item)) {
                firmware_url_ = url_item->valuestring;
            }
        }
    }

    // Extract activation challenge
    cJSON* activation_challenge_item = cJSON_GetObjectItem(json, "activation_challenge");
    if (activation_challenge_item && cJSON_IsString(activation_challenge_item)) {
        activation_challenge_ = activation_challenge_item->valuestring;
        has_activation_challenge_ = true;
    }

    // Extract activation code
    cJSON* activation_code_item = cJSON_GetObjectItem(json, "activation_code");
    if (activation_code_item && cJSON_IsString(activation_code_item)) {
        activation_code_ = activation_code_item->valuestring;
        has_activation_code_ = true;
    }

    // Extract activation message
    cJSON* activation_message_item = cJSON_GetObjectItem(json, "activation_message");
    if (activation_message_item && cJSON_IsString(activation_message_item)) {
        activation_message_ = activation_message_item->valuestring;
    }

    // Extract serial number
    cJSON* serial_number_item = cJSON_GetObjectItem(json, "serial_number");
    if (serial_number_item && cJSON_IsString(serial_number_item)) {
        serial_number_ = serial_number_item->valuestring;
        has_serial_number_ = true;
    }

    // Extract server time
    cJSON* server_time_item = cJSON_GetObjectItem(json, "server_time");
    if (server_time_item && cJSON_IsNumber(server_time_item)) {
        // We could store this if needed, but just set the flag for now
        has_server_time_ = true;
    }

    // Extract MQTT config
    cJSON* mqtt_config_item = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_config_item && cJSON_IsObject(mqtt_config_item)) {
        has_mqtt_config_ = true;
        // Here we would typically update MQTT settings, but that's likely handled elsewhere
    }

    // Extract WebSocket config
    cJSON* websocket_config_item = cJSON_GetObjectItem(json, "websocket");
    if (websocket_config_item && cJSON_IsObject(websocket_config_item)) {
        has_websocket_config_ = true;
        // Here we would typically update WebSocket settings, but that's likely handled elsewhere
    }

    // Clean up
    cJSON_Delete(json);

    ESP_LOGI(TAG, "Version check completed. Current: %s, Available: %s, New: %s", 
             current_version_.c_str(), 
             firmware_version_.c_str(), 
             has_new_version_ ? "Yes" : "No");

    return ESP_OK;
}

