void Ota::MarkCurrentVersionValid()
{
    const esp_partition_t* current_partition = esp_ota_get_running_partition();
    if (current_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Skip validation for factory partition
    if (current_partition->type == ESP_PARTITION_TYPE_APP && 
        strncmp(current_partition->label, "factory", 7) == 0) {
        ESP_LOGI(TAG, "Running factory partition, skipping validation.");
        return;
    }

    esp_err_t err = esp_ota_mark_app_valid_cancel_rollback();
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to mark app as valid: %s", esp_err_to_name(err));
    } else {
        ESP_LOGI(TAG, "Successfully marked current version as valid.");
    }
}

