bool Ota::Upgrade(const std::string& firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    if (firmware_url.empty()) {
        ESP_LOGE(TAG, "Invalid firmware URL");
        return false;
    }

    esp_err_t err;
    const esp_partition_t* update_partition = nullptr;
    esp_ota_handle_t update_handle = 0;
    size_t content_length = 0;
    size_t total_written = 0;
    int last_progress = -1;

    // Find OTA update partition
    update_partition = esp_ota_get_next_update_partition(nullptr);
    if (update_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to find OTA partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             update_partition->subtype, update_partition->address);

    // Begin OTA update
    err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Setup HTTP client for firmware download
    auto http_client = std::make_unique<Http>();
    if (!http_client) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        esp_ota_abort(update_handle);
        return false;
    }

    // Configure HTTP request
    http_client->SetUrl(firmware_url);
    http_client->SetMethod(HTTP_GET);

    // Add headers if needed
    http_client->AddHeader("User-Agent", "ESP32-OTA-Updater");

    // Open connection
    if (!http_client->Open()) {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        esp_ota_abort(update_handle);
        return false;
    }

    // Get content length
    content_length = http_client->GetContentLength();
    if (content_length == 0) {
        ESP_LOGW(TAG, "Content length is zero, proceeding anyway");
    }

    ESP_LOGI(TAG, "Firmware size: %d bytes", content_length);

    // Download and write firmware
    const size_t buffer_size = 4096;
    std::vector<uint8_t> buffer(buffer_size);
    uint32_t start_time = millis();
    size_t last_reported_bytes = 0;
    uint32_t last_report_time = start_time;

    while (true) {
        int bytes_read = http_client->Read(buffer.data(), buffer_size);

        if (bytes_read < 0) {
            ESP_LOGE(TAG, "HTTP read error");
            esp_ota_abort(update_handle);
            http_client->Close();
            return false;
        }

        if (bytes_read == 0) {
            // End of stream
            break;
        }

        // Write data to OTA partition
        err = esp_ota_write(update_handle, buffer.data(), bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            esp_ota_abort(update_handle);
            http_client->Close();
            return false;
        }

        total_written += bytes_read;

        // Report progress if callback provided
        if (callback && content_length > 0) {
            uint32_t current_time = millis();
            int progress = (total_written * 100) / content_length;

            // Report progress every 1% or every second
            if (progress != last_progress || (current_time - last_report_time) >= 1000) {
                size_t speed = 0;
                if (current_time > start_time) {
                    speed = (total_written * 1000) / (current_time - start_time);
                }

                callback(progress, speed);
                last_progress = progress;
                last_report_time = current_time;
            }
        }
    }

    http_client->Close();

    // Final progress report
    if (callback && content_length > 0) {
        uint32_t current_time = millis();
        size_t speed = 0;
        if (current_time > start_time) {
            speed = (total_written * 1000) / (current_time - start_time);
        }
        callback(100, speed);
    }

    ESP_LOGI(TAG, "Total written: %d bytes", total_written);

    // End OTA update
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Validate firmware image
    esp_app_desc_t app_desc;
    err = esp_ota_get_partition_description(update_partition, &app_desc);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get partition description (%s)", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "New firmware version: %s", app_desc.version);

    // Set boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade completed successfully");
    return true;
}

