std::vector<int> Ota::ParseVersion(const std::string& version)
{
    std::vector<int> result;
    std::stringstream ss(version);
    std::string segment;

    while (std::getline(ss, segment, '.')) {
        try {
            if (!segment.empty()) {
                result.push_back(std::stoi(segment));
            }
        } catch (const std::invalid_argument&) {
            // Ignore invalid segments or log error if needed
            ESP_LOGW(TAG, "Invalid version segment: %s", segment.c_str());
        } catch (const std::out_of_range&) {
            // Handle numbers too large to fit in int
            ESP_LOGW(TAG, "Version segment out of range: %s", segment.c_str());
        }
    }

    return result;
}

