bool Ota::IsNewVersionAvailable(const std::string& currentVersion, const std::string& newVersion)
{
    std::vector<int> current = ParseVersion(currentVersion);
    std::vector<int> candidate = ParseVersion(newVersion);

    size_t maxLen = std::max(current.size(), candidate.size());

    for (size_t i = 0; i < maxLen; ++i) {
        int curr = (i < current.size()) ? current[i] : 0;
        int cand = (i < candidate.size()) ? candidate[i] : 0;

        if (cand > curr) {
            return true;
        } else if (cand < curr) {
            return false;
        }
    }

    // All components were equal
    return false;
}

