std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_) {
        return "{}";
    }

    cJSON* root = cJSON_CreateObject();
    if (!root) {
        ESP_LOGE(TAG, "Failed to create JSON object");
        return "{}";
    }

    cJSON_AddStringToObject(root, "serial", serial_number_.c_str());
    cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());

#ifdef SOC_HMAC_SUPPORTED
    // Prepare message to sign: serial + challenge
    std::string message = serial_number_ + activation_challenge_;
    uint8_t hmac[32];

    esp_err_t ret = esp_hmac_calculate(HMAC_KEY0, reinterpret_cast<const uint8_t*>(message.c_str()), message.length(), hmac);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to calculate HMAC: %s", esp_err_to_name(ret));
        cJSON_Delete(root);
        return "{}";
    }

    // Convert raw HMAC bytes into hex string
    char hmac_hex[65];  // 32 bytes * 2 chars each + null terminator
    for (int i = 0; i < 32; ++i) {
        sprintf(&hmac_hex[i * 2], "%02x", hmac[i]);
    }
    hmac_hex[64] = '\0';

    cJSON_AddStringToObject(root, "signature", hmac_hex);
#endif

    char* json_str = cJSON_PrintUnformatted(root);
    std::string result(json_str ? json_str : "{}");

    if (json_str) {
        free(json_str);
    }
    cJSON_Delete(root);

    return result;
}

