esp_err_t Ota::Activate()
{
    ESP_LOGI(TAG, "Starting firmware activation");

    // Setup HTTP client
    auto http_client = SetupHttp();
    if (!http_client) {
        ESP_LOGE(TAG, "Failed to setup HTTP client for activation");
        return ESP_FAIL;
    }

    // Construct activation URL
    std::string activation_url = Settings::GetInstance().GetApiBaseUrl() + "/activate";

    // Prepare payload
    std::string payload = GetActivationPayload();

    // Set HTTP headers
    http_client->SetHeader("Content-Type", "application/json");
    http_client->SetHeader("Accept", "application/json");

    // Send POST request
    int http_status = http_client->Post(activation_url, payload);

    // Handle response
    if (http_status == 200) {
        ESP_LOGI(TAG, "Activation successful");

        // Parse response if needed
        std::string response = http_client->GetResponseBody();
        if (!response.empty()) {
            cJSON* json = cJSON_Parse(response.c_str());
            if (json) {
                cJSON* message = cJSON_GetObjectItem(json, "message");
                if (message && cJSON_IsString(message)) {
                    activation_message_ = message->valuestring;
                }

                cJSON* activation_code = cJSON_GetObjectItem(json, "activation_code");
                if (activation_code && cJSON_IsString(activation_code)) {
                    activation_code_ = activation_code->valuestring;
                    has_activation_code_ = true;
                }

                cJSON_Delete(json);
            }
        }

        return ESP_OK;
    } else if (http_status == 400) {
        ESP_LOGW(TAG, "Bad request during activation");
        activation_message_ = "Invalid activation request";
        return ESP_ERR_INVALID_ARG;
    } else if (http_status == 401) {
        ESP_LOGW(TAG, "Unauthorized during activation");
        activation_message_ = "Activation not authorized";
        return ESP_ERR_INVALID_STATE;
    } else if (http_status == 404) {
        ESP_LOGW(TAG, "Activation endpoint not found");
        activation_message_ = "Activation service unavailable";
        return ESP_ERR_NOT_FOUND;
    } else if (http_status >= 500) {
        ESP_LOGE(TAG, "Server error during activation: %d", http_status);
        activation_message_ = "Server error during activation";
        return ESP_ERR_HTTP_BASE + (http_status - 500);
    } else {
        ESP_LOGE(TAG, "Unexpected HTTP status during activation: %d", http_status);
        activation_message_ = "Unknown error during activation";
        return ESP_FAIL;
    }
}

