std::string Settings::GetString(const std::string& key, const std::string& default_value) {
    size_t required_size = 0;
    esp_err_t err = nvs_get_str(nvs_handle_, key.c_str(), nullptr, &required_size);
    if (err != ESP_OK || required_size == 0) {
        ESP_LOGW(TAG, "Failed to read key '%s' from NVS: %s", key.c_str(), esp_err_to_name(err));
        return default_value;
    }

    std::string value(required_size - 1, '\0'); // subtract 1 to exclude null terminator
    err = nvs_get_str(nvs_handle_, key.c_str(), &value[0], &required_size);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Failed to read key '%s' from NVS: %s", key.c_str(), esp_err_to_name(err));
        return default_value;
    }

    // Remove any trailing null characters just in case
    while (!value.empty() && value.back() == '\0') {
        value.pop_back();
    }

    return value;
}

