void Settings::EraseAll()
{
    if (!read_write_) {
        ESP_LOGW(TAG, "Cannot erase settings: NVS namespace '%s' is read-only.", ns_.c_str());
        return;
    }

    esp_err_t err = nvs_erase_all(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase all settings in namespace '%s': %s", ns_.c_str(), esp_err_to_name(err));
        return;
    }

    err = nvs_commit(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to commit erase operation in namespace '%s': %s", ns_.c_str(), esp_err_to_name(err));
        return;
    }

    ESP_LOGI(TAG, "Successfully erased all settings in namespace '%s'.", ns_.c_str());
}

