esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // First call to get initial state
    UBaseType_t uxArraySize = uxTaskGetNumberOfTasks();
    std::vector<TaskStatus_t> pxTaskStatusArray1(uxArraySize);
    uint32_t ulTotalRunTime1;

    UBaseType_t uxResult1 = uxTaskGetSystemState(pxTaskStatusArray1.data(), uxArraySize, &ulTotalRunTime1);

    if (uxResult1 != uxArraySize) {
        ESP_LOGE(TAG, "Failed to retrieve task statuses before delay.");
        return ESP_FAIL;
    }

    vTaskDelay(xTicksToWait);

    // Second call to get final state
    uxArraySize = uxTaskGetNumberOfTasks();
    std::vector<TaskStatus_t> pxTaskStatusArray2(uxArraySize);
    uint32_t ulTotalRunTime2;

    UBaseType_t uxResult2 = uxTaskGetSystemState(pxTaskStatusArray2.data(), uxArraySize, &ulTotalRunTime2);

    if (uxResult2 != uxArraySize) {
        ESP_LOGE(TAG, "Failed to retrieve task statuses after delay.");
        return ESP_FAIL;
    }

    uint32_t ulTotalRunTimeDiff = ulTotalRunTime2 - ulTotalRunTime1;

    if (ulTotalRunTimeDiff == 0) {
        ESP_LOGW(TAG, "No change in total run time; skipping CPU usage calculation.");
        return ESP_OK;
    }

    // Map task handles from first snapshot
    std::map<TaskHandle_t, TaskStatus_t*> taskMap1;
    for (auto& task : pxTaskStatusArray1) {
        taskMap1[task.xHandle] = &task;
    }

    ESP_LOGI(TAG, "\nTask CPU Usage:");
    ESP_LOGI(TAG, "%-16s %-6s %s", "Task Name", "CoreID", "CPU %");

    // Process second snapshot
    std::set<TaskHandle_t> seenHandles;
    for (const auto& task2 : pxTaskStatusArray2) {
        seenHandles.insert(task2.xHandle);
        char coreIdStr[8];
        snprintf(coreIdStr, sizeof(coreIdStr), "CPU%d", task2.xCoreID);

        auto it = taskMap1.find(task2.xHandle);
        if (it != taskMap1.end()) {
            // Task existed before
            TaskStatus_t* task1 = it->second;
            uint32_t ulRunTimeDiff = task2.ulRunTimeCounter - task1->ulRunTimeCounter;
            float fPercentage = (static_cast<float>(ulRunTimeDiff) / ulTotalRunTimeDiff) * 100.0f;
            ESP_LOGI(TAG, "%-16s %-6s %.2f%%", task2.pcTaskName, coreIdStr, fPercentage);
        } else {
            // New task
            ESP_LOGI(TAG, "%-16s %-6s [New]", task2.pcTaskName, coreIdStr);
        }
    }

    // Detect deleted tasks
    for (const auto& pair : taskMap1) {
        if (seenHandles.find(pair.first) == seenHandles.end()) {
            ESP_LOGI(TAG, "%-16s %-6s [Deleted]", pair.second->pcTaskName, "N/A");
        }
    }

    return ESP_OK;
}

