bool AudioCodec::InputData(std::vector<int16_t>& data)
{
    if (!input_enabled_) {
        return false;
    }

    // Resize the vector to hold one frame of audio data
    data.resize(AUDIO_CODEC_DMA_FRAME_NUM);

    // Read audio samples into the vector
    int samples_read = Read(data.data(), AUDIO_CODEC_DMA_FRAME_NUM);

    // Check if reading was successful
    if (samples_read <= 0) {
        data.clear();
        return false;
    }

    // Resize vector to actual number of samples read (in case it's less than requested)
    if (samples_read < AUDIO_CODEC_DMA_FRAME_NUM) {
        data.resize(samples_read);
    }

    return true;
}

