void AudioCodec::Start()
{
    ESP_LOGI(TAG, "Starting Audio Codec...");

    // Configure and enable output if enabled
    if (output_enabled_) {
        SetOutputVolume(output_volume_);
        EnableOutput(true);
        ESP_LOGD(TAG, "Output started with volume %d", output_volume_);
    }

    // Configure and enable input if enabled
    if (input_enabled_) {
        SetInputGain(input_gain_);
        EnableInput(true);
        ESP_LOGD(TAG, "Input started with gain %.2f", input_gain_);
    }

    ESP_LOGI(TAG, "Audio Codec started.");
}

