void AudioCodec::SetOutputVolume(int volume)
{
    // Clamp volume to valid range 0-100
    if (volume < 0) {
        volume = 0;
    } else if (volume > 100) {
        volume = 100;
    }

    // Update internal volume state
    output_volume_ = volume;

    // Log the volume change for debugging
    ESP_LOGI(TAG, "Output volume set to %d", volume);

    // Save the volume setting persistently
    // Note: Since we can't access settings.h directly, we'll use a try/catch approach
    // In practice, this would use the Settings class to save to NVS
    try {
        // This would normally be something like:
        // Settings settings("audio", true);
        // settings.SetInt("output_volume", volume);
        // settings.Save();

        // For now, we'll just log that persistence would happen here
        ESP_LOGD(TAG, "Volume %d would be saved to persistent storage", volume);
    } catch (...) {
        ESP_LOGW(TAG, "Failed to save volume to persistent storage");
    }
}

