Es8388AudioCodec::Es8388AudioCodec(void* i2c_master_handle, i2c_port_t i2c_port, int input_sample_rate, int output_sample_rate,
    gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din,
    gpio_num_t pa_pin, uint8_t es8388_addr, bool input_reference) {

    ESP_LOGI(TAG, "Initializing ES8388 audio codec");

    // Store PA pin
    pa_pin_ = pa_pin;

    // Initialize I2C control interface
    esp_codec_i2c_cfg_t i2c_cfg = {
        .port = i2c_port,
        .addr = es8388_addr,
    };
    ctrl_if_ = esp_codec_new_i2c_ctrl(&i2c_cfg);
    if (!ctrl_if_) {
        ESP_LOGE(TAG, "Failed to create I2C control interface");
        return;
    }

    // Create duplex channels (I2S interfaces)
    CreateDuplexChannels(mclk, bclk, ws, dout, din);

    if (!data_if_) {
        ESP_LOGE(TAG, "Failed to create data interface");
        return;
    }

    // Get GPIO interface
    gpio_if_ = esp_codec_new_gpio();

    // Initialize codec interface
    esp_codec_es8388_cfg_t codec_cfg = {
        .ctrl_if = ctrl_if_,
    };
    codec_if_ = esp_codec_new_es8388(&codec_cfg);
    if (!codec_if_) {
        ESP_LOGE(TAG, "Failed to create codec interface");
        return;
    }

    // Configure output device
    esp_codec_dev_cfg_t output_dev_cfg = {
        .dev_type = ESP_CODEC_DEV_TYPE_OUT,
        .codec_type = ESP_CODEC_TYPE_ES8388,
        .codec_if = codec_if_,
        .data_if = data_if_,
        .gpio_if = gpio_if_,
        .sample_rate = output_sample_rate,
    };
    output_dev_ = esp_codec_dev_new(&output_dev_cfg);
    if (!output_dev_) {
        ESP_LOGE(TAG, "Failed to create output device");
        return;
    }

    // Configure input device
    esp_codec_dev_cfg_t input_dev_cfg = {
        .dev_type = ESP_CODEC_DEV_TYPE_IN,
        .codec_type = ESP_CODEC_TYPE_ES8388,
        .codec_if = codec_if_,
        .data_if = data_if_,
        .gpio_if = gpio_if_,
        .sample_rate = input_sample_rate,
    };
    input_dev_ = esp_codec_dev_new(&input_dev_cfg);
    if (!input_dev_) {
        ESP_LOGE(TAG, "Failed to create input device");
        return;
    }

    // Configure reference input if enabled
    if (input_reference) {
        ESP_LOGI(TAG, "Configuring reference input for acoustic echo cancellation");
        // Additional configuration for reference input would go here
    }

    // Initialize PA pin if valid
    if (pa_pin_ != GPIO_NUM_NC) {
        gpio_set_direction(pa_pin_, GPIO_MODE_OUTPUT);
        gpio_set_level(pa_pin_, 0); // Start with PA disabled
    }

    ESP_LOGI(TAG, "ES8388 audio codec initialized successfully");
}

