void Es8388AudioCodec::EnableOutput(bool enable) {
    std::lock_guard<std::mutex> lock(data_if_mutex_);

    if (enable == output_enabled_) {
        return;
    }

    if (enable) {
        // Enable the power amplifier pin if configured
        if (pa_pin_ != GPIO_NUM_NC) {
            gpio_set_level(pa_pin_, 1);
        }

        // Configure and open output device if not already done
        if (output_dev_ == nullptr && codec_if_ != nullptr) {
            esp_codec_dev_cfg_t devcfg = {
                .dev_type = ESP_CODEC_DEV_TYPE_OUT,
                .codec_if = codec_if_,
                .gpio_if = gpio_if_,
                .hz = (unsigned int)output_sample_rate_,
                .master_role = false,
            };
            output_dev_ = esp_codec_dev_new(&devcfg);
        }

        if (output_dev_) {
            // Configure output parameters
            esp_codec_dev_open(output_dev_, &(esp_codec_dev_sample_info_t){
                .sample_rate = (unsigned int)output_sample_rate_,
                .channel = (unsigned int)output_channels_,
                .bits_per_sample = 16,
                .stream_type = ESP_CODEC_DEV_STREAM_TYPE_OUT,
            });

            // Set initial volume
            esp_codec_dev_set_out_vol(output_dev_, output_volume_);
        }
    } else {
        // Disable output
        if (output_dev_) {
            esp_codec_dev_close(output_dev_);
        }

        // Disable the power amplifier pin if configured
        if (pa_pin_ != GPIO_NUM_NC) {
            gpio_set_level(pa_pin_, 0);
        }
    }

    // Call parent class implementation to update the flag
    AudioCodec::EnableOutput(enable);
}

