int Es8388AudioCodec::Write(const int16_t* data, int samples) {
    // Check if output is enabled
    if (!output_enabled_) {
        return 0;
    }

    // Check if the device is valid
    if (output_dev_ == nullptr) {
        ESP_LOGE(TAG, "Output device is not initialized");
        return 0;
    }

    // Check if data pointer is valid
    if (data == nullptr) {
        ESP_LOGE(TAG, "Invalid data pointer");
        return 0;
    }

    // Convert sample count to byte size
    size_t bytes_to_write = samples * sizeof(int16_t);

    // Write data to the output device
    esp_err_t result = esp_codec_dev_write(output_dev_, (void*)data, bytes_to_write);
    if (result != ESP_OK) {
        ESP_LOGW(TAG, "Failed to write audio data, err=%d", result);
        return 0;
    }

    // Return number of samples written
    return samples;
}

