AudioDebugger::AudioDebugger()
{
#if CONFIG_USE_AUDIO_DEBUGGER
    // Define default values; these would typically come from Kconfig
    const char* server_ip = CONFIG_AUDIO_DEBUGGER_SERVER_IP;
    int server_port = CONFIG_AUDIO_DEBUGGER_SERVER_PORT;

    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_sockfd_ < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket: errno %d", errno);
        return;
    }

    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(server_port);

    if (inet_aton(server_ip, &udp_server_addr_.sin_addr) == 0) {
        ESP_LOGE(TAG, "Invalid server IP address: %s", server_ip);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "UDP socket initialized. Sending to %s:%d", server_ip, server_port);
#else
    ESP_LOGW(TAG, "AudioDebugger is disabled via CONFIG_USE_AUDIO_DEBUGGER");
#endif
}

