#if CONFIG_USE_AUDIO_DEBUGGER

void AudioDebugger::Feed(const std::vector<int16_t>& data)
{
    if (udp_sockfd_ < 0) {
        ESP_LOGE(TAG, "UDP socket not initialized");
        return;
    }

    if (data.empty()) {
        ESP_LOGW(TAG, "No data to send");
        return;
    }

    const size_t data_size_bytes = data.size() * sizeof(int16_t);
    const char* byte_data = reinterpret_cast<const char*>(data.data());

    ssize_t sent_bytes = sendto(udp_sockfd_, byte_data, data_size_bytes, 0,
                                (struct sockaddr*)&udp_server_addr_, sizeof(udp_server_addr_));

    if (sent_bytes < 0) {
        ESP_LOGE(TAG, "Failed to send audio data: %s", strerror(errno));
    } else if (static_cast<size_t>(sent_bytes) != data_size_bytes) {
        ESP_LOGW(TAG, "Incomplete data sent: %d/%zu bytes", static_cast<int>(sent_bytes), data_size_bytes);
    } else {
        ESP_LOGD(TAG, "Sent %zu bytes of audio data", data_size_bytes);
    }
}

#endif // CONFIG_USE_AUDIO_DEBUGGER

