AfeWakeWord::~AfeWakeWord() {
    // Stop any ongoing operations first
    Stop();

    // Deinitialize AFE SR data if valid
    if (afe_iface_ && afe_data_) {
        afe_iface_->destroy(afe_data_);
        afe_data_ = nullptr;
    }

    // Free wake word encode task resources if allocated
    if (wake_word_encode_task_) {
        vTaskDelete(wake_word_encode_task_);
        wake_word_encode_task_ = nullptr;
    }

    if (wake_word_encode_task_stack_) {
        free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    if (wake_word_encode_task_buffer_) {
        free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }

    // Delete the event group
    if (event_group_) {
        vEventGroupDelete(event_group_);
        event_group_ = nullptr;
    }

    // Free wakenet model string if allocated
    if (wakenet_model_) {
        free(wakenet_model_);
        wakenet_model_ = nullptr;
    }

    // Clear internal buffers
    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        wake_word_pcm_.clear();
        wake_word_opus_.clear();
    }
}

