bool AfeWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    codec_ = codec;
    models_ = models_list;

    // Initialize models if not provided
    if (models_ == nullptr) {
        models_ = esp_srmodel_init("model");
        if (models_ == nullptr) {
            ESP_LOGE(TAG, "Failed to initialize speech recognition models");
            return false;
        }
    }

    // Get wake word model
    wakenet_model_ = esp_srmodel_filter(models_, ESP_WAKENET_PREFIX, NULL);
    if (wakenet_model_ == nullptr) {
        ESP_LOGE(TAG, "Failed to find wake word model");
        return false;
    }

    // Determine input format based on codec configuration
    int ref_num = codec_->input_reference() ? 1 : 0;
    std::string input_format;

    for (int i = 0; i < codec_->input_channels() - ref_num; i++) {
        input_format.push_back('M');  // Microphone input
    }
    for (int i = 0; i < ref_num; i++) {
        input_format.push_back('R');  // Reference input
    }

    // Initialize AFE configuration
    afe_config_t* afe_config = afe_config_init(input_format.c_str(), wakenet_model_, AFE_TYPE_WAKE_WORD, AFE_MODE_HIGH_PERF);
    if (afe_config == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize AFE configuration");
        return false;
    }

    // Configure AFE parameters
    afe_config->aec_mode = AEC_MODE_VOIP_HIGH_PERF;
    afe_config->vad_mode = VAD_MODE_0;
    afe_config->vad_min_noise_ms = 100;
    afe_config->memory_alloc_mode = AFE_MEMORY_ALLOC_MORE_PSRAM;

    // Configure noise suppression
    char* ns_model_name = esp_srmodel_filter(models_, ESP_NSNET_PREFIX, NULL);
    if (ns_model_name != nullptr) {
        afe_config->ns_init = true;
        afe_config->ns_model_name = ns_model_name;
        afe_config->afe_ns_mode = AFE_NS_MODE_NET;
    } else {
        afe_config->ns_init = false;
    }

    // Configure automatic gain control
    afe_config->agc_init = false;

    // Configure AEC and VAD based on device capability
#ifdef CONFIG_USE_DEVICE_AEC
    afe_config->aec_init = true;
    afe_config->vad_init = false;
#else
    afe_config->aec_init = false;
    afe_config->vad_init = true;
#endif

    // Initialize AFE interface and data
    afe_iface_ = esp_afe_handle_from_config(afe_config);
    if (afe_iface_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get AFE handle");
        return false;
    }

    afe_data_ = afe_iface_->create_from_config(afe_config);
    if (afe_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create AFE data");
        return false;
    }

    // Create event group for task synchronization
    event_group_ = xEventGroupCreate();
    if (event_group_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create event group");
        return false;
    }

    // Allocate memory for task
    wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_calloc(1, sizeof(StaticTask_t), MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    wake_word_encode_task_stack_ = (StackType_t*)heap_caps_calloc(1, 4096, MALLOC_CAP_SPIRAM);

    if (wake_word_encode_task_buffer_ == nullptr || wake_word_encode_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for wake word encode task");
        return false;
    }

    // Create audio detection task
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            auto this_ = (AfeWakeWord*)arg;
            this_->AudioDetectionTask();
            vTaskDelete(NULL);
        },
        "wake_word_detection",
        4096,
        this,
        5,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create wake word detection task");
        return false;
    }

    ESP_LOGI(TAG, "AFE wake word initialized successfully");
    return true;
}

