void AfeWakeWord::Feed(const std::vector<int16_t>& data) {
    // Check if AFE data buffer is initialized
    if (afe_data_ == nullptr || afe_iface_ == nullptr) {
        ESP_LOGW(TAG, "AFE not initialized, dropping audio data");
        return;
    }

    // Check if we have data to process
    if (data.empty()) {
        return;
    }

    // Feed the audio data to the AFE processing pipeline
    // Using the standard pattern for ESP AFE SR interface
    afe_iface_->feed(afe_data_, (int16_t*)data.data(), data.size());
}

