void AfeWakeWord::AudioDetectionTask() {
    ESP_LOGI(TAG, "Starting audio detection task");

    // Buffer for audio data processing
    const int feed_size = GetFeedSize();
    std::vector<int16_t> audio_chunk(feed_size);

    while (true) {
        // Check if detection should continue running
        EventBits_t bits = xEventGroupGetBits(event_group_);
        if (!(bits & DETECTION_RUNNING_EVENT)) {
            break;
        }

        // Feed audio data to AFE SR interface
        int feedback = afe_iface_->fetch(afe_data_, audio_chunk.data());

        // Check if wake word was detected
        if (feedback == FEEDBACK_FETCH_WAKENET) {
            // Get wake word ID from AFE
            int wake_word_id = afe_iface_->get_wakenet_result(afe_data_);

            if (wake_word_id >= 0 && wake_word_id < static_cast<int>(wake_words_.size())) {
                // Store the detected wake word
                last_detected_wake_word_ = wake_words_[wake_word_id];

                // Store the wake word audio data
                StoreWakeWordData(audio_chunk.data(), audio_chunk.size());

                // Trigger callback if registered
                if (wake_word_detected_callback_) {
                    wake_word_detected_callback_(last_detected_wake_word_);
                }

                ESP_LOGI(TAG, "Wake word detected: %s", last_detected_wake_word_.c_str());
            }
        }
        else if (feedback == FEEDBACK_FETCH_NSNET) {
            // Handle noise suppression if needed
            // The audio_chunk now contains processed audio data
        }
        else if (feedback == FEEDBACK_FETCH_NONE) {
            // No specific action needed, continue monitoring
        }

        // Small delay to prevent busy waiting
        vTaskDelay(1);
    }

    ESP_LOGI(TAG, "Audio detection task stopped");
}

