void AfeWakeWord::StoreWakeWordData(const int16_t* data, size_t size) {
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Assuming 16kHz sample rate for wake word detection
    // 2 seconds of audio at 16kHz = 32000 samples
    constexpr size_t kMaxSamples = 32000;

    // Add new data to the buffer
    wake_word_pcm_.emplace_back(data, data + size);

    // Calculate total samples in buffer
    size_t total_samples = 0;
    for (const auto& segment : wake_word_pcm_) {
        total_samples += segment.size();
    }

    // Remove old segments if we exceed the 2-second limit
    while (total_samples > kMaxSamples && !wake_word_pcm_.empty()) {
        total_samples -= wake_word_pcm_.front().size();
        wake_word_pcm_.pop_front();
    }
}

