void CustomWakeWord::ParseWakenetModelConfig()
{
    // Construct the path to index.json
    std::string config_path = std::string(MODEL_PATH) + "/index.json";

    // Read the JSON file content
    std::string json_content;
    if (!Assets::ReadFile(config_path, json_content)) {
        ESP_LOGE(TAG, "Failed to read config file: %s", config_path.c_str());
        return;
    }

    // Parse JSON
    cJSON* root = cJSON_Parse(json_content.c_str());
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse JSON config file: %s", config_path.c_str());
        return;
    }

    // Parse language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item && cJSON_IsString(language_item)) {
        language_ = std::string(cJSON_GetStringValue(language_item));
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    }

    // Parse duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Parsed duration: %d ms", duration_);
    }

    // Parse threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item && cJSON_IsNumber(threshold_item)) {
        threshold_ = threshold_item->valuedouble;
        ESP_LOGI(TAG, "Parsed threshold: %.2f", threshold_);
    }

    // Parse commands
    cJSON* commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array && cJSON_IsArray(commands_array)) {
        commands_.clear();
        int commands_count = cJSON_GetArraySize(commands_array);

        for (int i = 0; i < commands_count; i++) {
            cJSON* command_item = cJSON_GetArrayItem(commands_array, i);
            if (command_item && cJSON_IsObject(command_item)) {
                Command cmd;

                cJSON* command_field = cJSON_GetObjectItem(command_item, "command");
                if (command_field && cJSON_IsString(command_field)) {
                    cmd.command = std::string(cJSON_GetStringValue(command_field));
                }

                cJSON* text_field = cJSON_GetObjectItem(command_item, "text");
                if (text_field && cJSON_IsString(text_field)) {
                    cmd.text = std::string(cJSON_GetStringValue(text_field));
                }

                cJSON* action_field = cJSON_GetObjectItem(command_item, "action");
                if (action_field && cJSON_IsString(action_field)) {
                    cmd.action = std::string(cJSON_GetStringValue(action_field));
                }

                if (!cmd.command.empty()) {
                    commands_.push_back(cmd);
                    ESP_LOGI(TAG, "Parsed command: %s, text: %s, action: %s", 
                             cmd.command.c_str(), cmd.text.c_str(), cmd.action.c_str());
                }
            }
        }
    }

    // Clean up
    cJSON_Delete(root);
}

