bool CustomWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    if (!codec || !models_list) {
        ESP_LOGE(TAG, "Invalid arguments: codec or models_list is null");
        return false;
    }

    codec_ = codec;
    models_ = models_list;

    // Find a suitable multinet model
    const esp_mn_model_t* selected_model = nullptr;
    for (int i = 0; i < models_->num; ++i) {
        const esp_mn_model_t* model = &models_->model[i];
        if (model && model->lang && strstr(model->lang, language_.c_str())) {
            selected_model = model;
            break;
        }
    }

    if (!selected_model) {
        ESP_LOGE(TAG, "No matching multinet model found for language: %s", language_.c_str());
        return false;
    }

    // Get the model interface
    multinet_ = selected_model->iface;
    if (!multinet_) {
        ESP_LOGE(TAG, "Failed to get multinet interface");
        return false;
    }

    // Create model data
    multinet_model_data_ = multinet_->create(selected_model->coefficient_model);
    if (!multinet_model_data_) {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Set detection threshold
    if (multinet_->set_det_threshold) {
        multinet_->set_det_threshold(threshold_, multinet_model_data_);
    }

    // Optional: Parse wakenet config if needed
    ParseWakenetModelConfig();

    // Example: Add some default commands (this should ideally come from assets/config)
    Command cmd{"turn_on_light", "开灯", "light_on"};
    commands_.push_back(cmd);

    // Register commands with the model
    for (const auto& command : commands_) {
        if (multinet_->add_command) {
            multinet_->add_command(multinet_model_data_, command.text.c_str(), 1); // Assuming ID=1
        }
    }

    ESP_LOGI(TAG, "CustomWakeWord initialized successfully.");
    return true;
}

