void CustomWakeWord::Feed(const std::vector<int16_t>& data)
{
    // Check if wake word detection is running
    if (!running_) {
        return;
    }

    // Handle empty data
    if (data.empty()) {
        return;
    }

    // Process audio data - extract left channel for stereo input
    std::vector<int16_t> processed_data;
    processed_data.reserve(data.size() / 2);

    // Assuming stereo interleaved data (left, right, left, right...)
    // Extract left channel only
    for (size_t i = 0; i < data.size(); i += 2) {
        processed_data.push_back(data[i]);
    }

    // Lock mutex for thread safety when accessing wake word PCM buffer
    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        wake_word_pcm_.push_back(std::move(processed_data));
    }

    // Wake up encoding task if it's waiting
    wake_word_cv_.notify_one();

    // Run wake word detection algorithm using multinet model
    if (multinet_ && multinet_model_data_) {
        // Get the latest audio chunk for detection
        const std::vector<int16_t>& audio_chunk = wake_word_pcm_.back();

        // Run multinet detection
        esp_mn_state_t result = multinet_->detect(multinet_model_data_, audio_chunk.data());

        // Check if wake word was detected
        if (result.wakeup_word_id > 0) {
            // Get wake word string from the model
            const char* wake_word_str = multinet_->getWakeWordName(multinet_model_data_, result.wakeup_word_id);

            if (wake_word_str) {
                std::string wake_word(wake_word_str);
                last_detected_wake_word_ = wake_word;

                // Stop further processing until reactivated
                running_ = false;

                // Trigger callback if set
                if (wake_word_detected_callback_) {
                    wake_word_detected_callback_(wake_word);
                }
            }
        }
    }
}

