void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& data) {
    if (data.empty()) {
        return;
    }

    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Add the new data chunk to the end of the deque
    wake_word_pcm_.push_back(data);

    // Determine the sample rate from the codec
    int sample_rate = 16000; // Default fallback
    if (codec_) {
        sample_rate = codec_->input_sample_rate();
    }

    // Calculate maximum samples for 2 seconds
    size_t max_samples = sample_rate * 2;

    // Calculate current total samples
    size_t total_samples = 0;
    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
    }

    // Remove old chunks from the front until we're within the 2-second limit
    while (!wake_word_pcm_.empty() && total_samples > max_samples) {
        total_samples -= wake_word_pcm_.front().size();
        wake_word_pcm_.pop_front();
    }
}

