void CustomWakeWord::EncodeWakeWordData() {
    // Avoid multiple concurrent encodings
    if (wake_word_encode_task_ != nullptr) {
        ESP_LOGW(TAG, "Encoding task already running");
        return;
    }

    // Allocate memory for task stack and TCB
    wake_word_encode_task_stack_ = static_cast<StackType_t*>(heap_caps_calloc(1, CONFIG_CUSTOM_WAKE_WORD_ENCODING_STACK_SIZE * sizeof(StackType_t), MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT));
    if (!wake_word_encode_task_stack_) {
        ESP_LOGE(TAG, "Failed to allocate stack for wake word encoding task");
        return;
    }

    wake_word_encode_task_buffer_ = static_cast<StaticTask_t*>(heap_caps_calloc(1, sizeof(StaticTask_t), MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT));
    if (!wake_word_encode_task_buffer_) {
        ESP_LOGE(TAG, "Failed to allocate task buffer for wake word encoding task");
        free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return;
    }

    // Launch the encoding task
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            CustomWakeWord* self = static_cast<CustomWakeWord*>(arg);

            // Acquire lock before processing
            std::unique_lock<std::mutex> lock(self->wake_word_mutex_);

            while (!self->wake_word_pcm_.empty()) {
                auto& pcm_segment = self->wake_word_pcm_.front();

                // Encode PCM -> Opus
                std::vector<uint8_t> opus_packet;
                if (self->codec_ && self->codec_->Encode(pcm_segment, opus_packet)) {
                    self->wake_word_opus_.push_back(std::move(opus_packet));
                } else {
                    ESP_LOGW(TAG, "Failed to encode PCM segment");
                }

                self->wake_word_pcm_.pop_front();
            }

            // Add termination marker (zero-length frame indicates end)
            self->wake_word_opus_.emplace_back(); 

            // Notify anyone waiting that Opus data is ready
            self->wake_word_cv_.notify_all();

            // Cleanup task resources
            free(self->wake_word_encode_task_stack_);
            self->wake_word_encode_task_stack_ = nullptr;

            free(self->wake_word_encode_task_buffer_);
            self->wake_word_encode_task_buffer_ = nullptr;

            self->wake_word_encode_task_ = nullptr;

            vTaskDelete(nullptr); // Delete current task
        },
        "WakeWordEncoder",
        CONFIG_CUSTOM_WAKE_WORD_ENCODING_STACK_SIZE,
        this,
        CONFIG_CUSTOM_WAKE_WORD_ENCODING_TASK_PRIORITY,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == NULL) {
        ESP_LOGE(TAG, "Failed to create wake word encoding task");

        free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;

        free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }
}

