bool CustomWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus) {
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there is data in the queue
    wake_word_cv_.wait(lock, [this] { return !wake_word_opus_.empty(); });

    // Retrieve the front element and remove it from the queue
    std::vector<uint8_t> data = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // Use swap to efficiently transfer ownership of the data
    opus.swap(data);

    // Return true if the retrieved data is non-empty
    return !opus.empty();
}

