void XL9555::SetOutputState(uint8_t bit, uint8_t level)
{
    // Read the current output register value (typically register 0x01 for XL9555)
    uint8_t data = ReadReg(0x01);

    // Set or clear the corresponding bit based on level
    if (level) {
        data |= (1 << bit);   // Set bit
    } else {
        data &= ~(1 << bit);  // Clear bit
    }

    // Write the updated value back to the output register
    WriteReg(0x01, data);
}

