void InitializeCamera() {
    // Configure camera power and reset through I/O expander
    // Assuming the XL9555 class has methods to control camera power/reset pins
    // Power down the camera first
    xl9555_in_->SetOutputState(5, 0); // Assuming pin 5 controls camera power
    vTaskDelay(pdMS_TO_TICKS(10));

    // Reset the camera
    xl9555_in_->SetOutputState(6, 0); // Assuming pin 6 controls camera reset
    vTaskDelay(pdMS_TO_TICKS(10));
    xl9555_in_->SetOutputState(6, 1);
    vTaskDelay(pdMS_TO_TICKS(10));

    // Power up the camera
    xl9555_in_->SetOutputState(5, 1);
    vTaskDelay(pdMS_TO_TICKS(10));

    static esp_cam_ctlr_dvp_pin_config_t dvp_pin_config = {
        .data_width = CAM_CTLR_DATA_WIDTH_8,
