#include <driver/spi_common.h>

#define TAG "atk_dnesp32s3"

extern "C" void atk_dnesp32s3()
{
    // Step 1: Initialize I2C Bus
    i2c_config_t i2c_conf;
    i2c_conf.mode = I2C_MODE_MASTER;
    i2c_conf.sda_io_num = GPIO_NUM_8;       // SDA Pin
    i2c_conf.scl_io_num = GPIO_NUM_9;       // SCL Pin
    i2c_conf.sda_pullup_en = GPIO_PULLUP_ENABLE;
    i2c_conf.scl_pullup_en = GPIO_PULLUP_ENABLE;
    i2c_conf.master.clk_speed = 400000;     // 400kHz clock speed

    esp_err_t ret = i2c_param_config(I2C_NUM_0, &i2c_conf);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "I2C parameter config failed");
        return;
    }

    ret = i2c_driver_install(I2C_NUM_0, I2C_MODE_MASTER, 0, 0, 0);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "I2C driver install failed");
        return;
    }

    // Step 2: Initialize SPI Bus for Display
    spi_bus_config_t buscfg = {};
    buscfg.mosi_io_num = GPIO_NUM_11;
    buscfg.miso_io_num = GPIO_NUM_13;
    buscfg.sclk_io_num = GPIO_NUM_12;
    buscfg.quadwp_io_num = -1;
    buscfg.quadhd_io_num = -1;
    buscfg.max_transfer_sz = LCD_H_RES * LCD_V_RES * sizeof(uint16_t);

    ret = spi_bus_initialize(SPI2_HOST, &buscfg, SPI_DMA_CH_AUTO);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "SPI bus initialization failed");
        return;
    }

    // Step 3: Initialize LCD Display (ST7789)
    LcdDisplay::init();

    // Step 4: Initialize Buttons
    Button::init();

    // Step 5: Initialize Camera
    esp32_camera_config_t cam_cfg = {
        .pin_pwdn = GPIO_NUM_40,
        .pin_reset = GPIO_NUM_39,
        .pin_xclk = GPIO_NUM_2,
        .pin_sscb_sda = GPIO_NUM_1,
        .pin_sscb_scl = GPIO_NUM_0,
        .pin_d7 = GPIO_NUM_21,
        .pin_d6 = GPIO_NUM_20,
        .pin_d5 = GPIO_NUM_19,
        .pin_d4 = GPIO_NUM_18,
        .pin_d3 = GPIO_NUM_17,
        .pin_d2 = GPIO_NUM_16,
        .pin_d1 = GPIO_NUM_15,
        .pin_d0 = GPIO_NUM_14,
        .pin_vsync = GPIO_NUM_5,
        .pin_href = GPIO_NUM_38,
        .pin_pclk = GPIO_NUM_3,
        .xclk_freq_hz = 20000000,
        .ledc_timer = LEDC_TIMER_0,
        .ledc_channel = LEDC_CHANNEL_0,
        .pixel_format = PIXFORMAT_JPEG,
        .frame_size = FRAMESIZE_QVGA,
        .jpeg_quality = 12,
        .fb_count = 2,
        .grab_mode = CAMERA_GRAB_WHEN_EMPTY,
    };

    ret = esp32_camera_init(&cam_cfg);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Camera init failed");
        return;
    }

    // Step 6: Initialize Audio Codec (ES8388)
    Es8388AudioCodec es8388_codec;
    ret = es8388_codec.init();
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "ES8388 audio codec init failed");
        return;
    }

    // Step 7: Initialize Onboard LED (Optional)
    SingleLed led(GPIO_NUM_48); // Assume LED on GPIO 48
    led.off();                  // Turn off initially

    ESP_LOGI(TAG, "Board ATK-DNESP32S3 initialized successfully.");
}

