void ReceiveWifiCredentialsFromAudio(Application *app,
                                     WifiManager *wifi_manager,
                                     Display *display,
                                     size_t timeout_ms) {
    ESP_LOGI(kLogTag, "Starting WiFi credential reception via audio...");

    // Step 1: Notify user about entering audio config mode
    display->ShowMessage("Listening for WiFi credentials...", Display::MessageType::INFO);

    // Step 2: Initialize AFSK decoder
    AfskDecoder decoder;

    // Step 3: Configure and start audio input stream
    AudioInputStream audio_stream;
    if (!audio_stream.Initialize()) {
        ESP_LOGE(kLogTag, "Failed to initialize audio input");
        display->ShowMessage("Audio init failed", Display::MessageType::ERROR);
        return;
    }

    TickType_t start_time = xTaskGetTickCount();
    TickType_t timeout_ticks = pdMS_TO_TICKS(timeout_ms);

    constexpr size_t kBufferSize = 512;
    int16_t buffer[kBufferSize];

    while ((xTaskGetTickCount() - start_time) < timeout_ticks) {
        // Step 4: Read audio data
        size_t bytes_read = audio_stream.Read(buffer, sizeof(buffer));
        if (bytes_read == 0) continue;

        size_t sample_count = bytes_read / sizeof(int16_t);

        // Optional: Convert stereo to mono
        std::vector<int16_t> mono_samples(sample_count / 2);
        for (size_t i = 0; i < sample_count; i += 2) {
            mono_samples[i / 2] = (buffer[i] + buffer[i + 1]) / 2;
        }

        // Step 5: Feed samples to AFSK decoder
        for (auto& sample : mono_samples) {
            if (decoder.ProcessSample(sample)) {
                // Full packet decoded!
                std::string ssid, password;
                if (decoder.GetDecodedCredentials(ssid, password)) {
                    ESP_LOGI(kLogTag, "Received SSID: %s", ssid.c_str());
                    ESP_LOGI(kLogTag, "Received Password: %s", password.c_str());

                    // Step 6: Connect to WiFi
                    display->ShowMessage("Connecting to WiFi...", Display::MessageType::INFO);
                    wifi_manager->ConnectToNetwork(ssid, password);

                    // Wait briefly for connection status update
                    vTaskDelay(pdMS_TO_TICKS(3000));

                    if (wifi_manager->IsConnected()) {
                        display->ShowMessage("Connected!", Display::MessageType::SUCCESS);
                        ESP_LOGI(kLogTag, "Successfully connected to WiFi.");
                    } else {
                        display->ShowMessage("Connection failed.", Display::MessageType::ERROR);
                        ESP_LOGW(kLogTag, "Failed to connect to WiFi network.");
                    }

                    return; // Exit once credentials processed
                }
            }
        }
    }

    // Timeout reached without valid credentials
    ESP_LOGW(kLogTag, "Timed out waiting for audio credentials.");
    display->ShowMessage("No credentials received.", Display::MessageType::WARNING);
}

FrequencyDetector::FrequencyDetector(float frequency, size_t window_size)
    : frequency_(frequency)
    , window_size_(window_size)
{
    // Calculate frequency bin: k = N * f / fs where f is normalized frequency
    frequency_bin_ = window_size_ * frequency_;

    // Calculate angular frequency: ω = 2π * f
    angular_frequency_ = 2.0f * M_PI * frequency_;

    // Calculate trigonometric coefficients
    cos_coefficient_ = std::cos(angular_frequency_);
    sin_coefficient_ = std::sin(angular_frequency_);

    // Calculate filter coefficient: 2 * cos(ω)
    filter_coefficient_ = 2.0f * cos_coefficient_;

    // Initialize state buffer with two zeros for S[-1] and S[-2]
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

void FrequencyDetector::Reset()
{
    state_buffer_.clear();
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

void FrequencyDetector::ProcessSample(float sample)
{
    // Apply the Goertzel algorithm difference equation
    // S[n] = x[n] + 2*cos(w) * S[n-1] - S[n-2]

    // Get previous state values
    float s_prev1 = 0.0f;
    float s_prev2 = 0.0f;

    if (state_buffer_.size() >= 1) {
        s_prev1 = state_buffer_[0];
    }
    if (state_buffer_.size() >= 2) {
        s_prev2 = state_buffer_[1];
    }

    // Calculate new state value
    float s_current = sample + filter_coefficient_ * s_prev1 - s_prev2;

    // Update state buffer (maintain only the last two values)
    if (state_buffer_.size() >= 2) {
        state_buffer_[1] = s_prev1;
        state_buffer_[0] = s_current;
    } else if (state_buffer_.size() == 1) {
        state_buffer_.push_front(s_current);
    } else {
        state_buffer_.push_front(s_current);
    }
}

float FrequencyDetector::GetAmplitude() const
{
    // Check if we have at least two samples in the buffer
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Get the last two samples from the state buffer
    // S[-1] is the most recent sample, S[-2] is the one before that
    float s_minus_1 = state_buffer_[0];  // Most recent
    float s_minus_2 = state_buffer_[1];  // Second most recent

    // Calculate real and imaginary parts using Goertzel algorithm
    // Real part = S[-1] - S[-2] * cos(w)
    float real_part = s_minus_1 - s_minus_2 * cos_coefficient_;

    // Imaginary part = S[-2] * sin(w)
    float imaginary_part = s_minus_2 * sin_coefficient_;

    // Calculate amplitude = sqrt(real^2 + imaginary^2) / (window_size / 2)
    float magnitude_squared = real_part * real_part + imaginary_part * imaginary_part;
    float amplitude = std::sqrt(magnitude_squared);

    // Normalize by half the window size
    return amplitude / (window_size_ / 2.0f);
}

AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t mark_frequency, size_t space_frequency,
                                         size_t bit_rate, size_t window_size)
    : input_buffer_size_(window_size)
    , output_sample_count_(0)
{
    // Validate that sample rate is divisible by bit rate
    if (sample_rate % bit_rate != 0) {
        ESP_LOGW(kLogTag, "Sample rate (%zu) is not divisible by bit rate (%zu)", sample_rate, bit_rate);
    }

    // Calculate samples per bit
    samples_per_bit_ = sample_rate / bit_rate;

    // Initialize input buffer with the specified size
    input_buffer_.resize(input_buffer_size_);

    // Create frequency detectors for mark and space tones
    // Normalize frequencies by dividing by sample rate
    float mark_normalized_freq = static_cast<float>(mark_frequency) / static_cast<float>(sample_rate);
    float space_normalized_freq = static_cast<float>(space_frequency) / static_cast<float>(sample_rate);

    mark_detector_ = std::make_unique<FrequencyDetector>(mark_normalized_freq, window_size);
    space_detector_ = std::make_unique<FrequencyDetector>(space_normalized_freq, window_size);
}

