std::vector<uint8_t> AfskDemodulator::ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    std::vector<uint8_t> bytes;
    size_t num_bits = bits.size();
    size_t num_bytes = num_bits / 8;

    // Reserve space to avoid repeated reallocations
    bytes.reserve(num_bytes);

    for (size_t i = 0; i < num_bytes; ++i) {
        uint8_t byte = 0;
        for (int bit_index = 0; bit_index < 8; ++bit_index) {
            // Assuming MSB first: shift left and OR the current bit
            byte = (byte << 1) | (bits[i * 8 + bit_index] ? 1 : 0);
        }
        bytes.push_back(byte);
    }

    return bytes;
}

