void Backlight::SetBrightness(uint8_t brightness, bool permanent)
{
    // Clamp brightness to valid range [0, 100]
    if (brightness > 100) {
        brightness = 100;
    }

    // Prevent redundant update
    if (brightness == brightness_) {
        return;
    }

    // Save permanently if needed
    if (permanent) {
        Settings::Set("backlight.brightness", brightness);
    }

    // Set target brightness
    target_brightness_ = brightness;

    // Stop any ongoing transition timer
    if (transition_timer_) {
        esp_timer_stop(transition_timer_);
    }

    // Calculate direction and start transition
    if (target_brightness_ > brightness_) {
        step_ = 1;
    } else {
        step_ = -1;
    }

    // Start transition timer (e.g., every 20ms)
    esp_timer_start_periodic(transition_timer_, 20000); // 20 ms in microseconds
}

