{
    // Clamp brightness to valid range [0, 100]
    if (brightness > 100) {
        brightness = 100;
    }

    // Convert percentage (0-100) to 10-bit duty value (0-1023)
    uint32_t duty = (static_cast<uint32_t>(brightness) * 1023) / 100;

    // Assuming LEDC channel was configured earlier (e.g., channel 0)
    // You may want to store channel/timer index in class members for flexibility
    constexpr ledc_channel_t CHANNEL = LEDC_CHANNEL_0;
    constexpr ledc_timer_t TIMER = LEDC_TIMER_0;

    // Set the duty and update the LEDC hardware
    ledc_set_duty_and_update(LEDC_LOW_SPEED_MODE, CHANNEL, duty, 0);
}

