#define TAG "Board"
#define NVS_NAMESPACE "storage"
#define NVS_KEY_UUID "device_uuid"

Board::Board() {
    esp_err_t err;
    nvs_handle_t handle;

    // Initialize NVS
    err = nvs_flash_init();
    if (err == ESP_ERR_NVS_NO_FREE_PAGES || err == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        ESP_ERROR_CHECK(nvs_flash_erase());
        err = nvs_flash_init();
    }
    ESP_ERROR_CHECK(err);

    // Open NVS handle
    err = nvs_open(NVS_NAMESPACE, NVS_READWRITE, &handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open NVS handle: %s", esp_err_to_name(err));
        return;
    }

    // Try to read existing UUID
    size_t required_size = 0;
    err = nvs_get_str(handle, NVS_KEY_UUID, NULL, &required_size);
    if (err != ESP_OK && err != ESP_ERR_NVS_NOT_FOUND) {
        ESP_LOGE(TAG, "Failed to query UUID length: %s", esp_err_to_name(err));
        nvs_close(handle);
        return;
    }

    if (err == ESP_OK && required_size > 0) {
        // UUID exists
        char* uuid_buffer = new char[required_size];
        err = nvs_get_str(handle, NVS_KEY_UUID, uuid_buffer, &required_size);
        if (err == ESP_OK) {
            uuid_ = std::string(uuid_buffer);
            ESP_LOGI(TAG, "Loaded UUID: %s", uuid_.c_str());
        } else {
            ESP_LOGE(TAG, "Failed to read UUID: %s", esp_err_to_name(err));
        }
        delete[] uuid_buffer;
    } else {
        // UUID does not exist, generate and save
        uuid_ = GenerateUuid();
        err = nvs_set_str(handle, NVS_KEY_UUID, uuid_.c_str());
        if (err == ESP_OK) {
            err = nvs_commit(handle);
            if (err == ESP_OK) {
                ESP_LOGI(TAG, "Generated and saved new UUID: %s", uuid_.c_str());
            } else {
                ESP_LOGE(TAG, "Failed to commit UUID to NVS: %s", esp_err_to_name(err));
            }
        } else {
            ESP_LOGE(TAG, "Failed to save UUID to NVS: %s", esp_err_to_name(err));
        }
    }

    nvs_close(handle);
}

