#include <cstdio>
#include <cstring>

std::string Board::GenerateUuid() {
    uint8_t uuid[16];

    // Fill all 16 bytes with random data
    uint32_t* rand_ptr = reinterpret_cast<uint32_t*>(uuid);
    for (int i = 0; i < 4; ++i) {
        rand_ptr[i] = esp_random();
    }

    // Set the version to 4 (top 4 bits of 7th byte = 0100)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Set the variant to RFC 4122 (top 2 bits of 9th byte = 10)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Format as 8-4-4-4-12 hex string with dashes
    char uuid_str[37];
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5], uuid[6], uuid[7],
             uuid[8], uuid[9], uuid[10], uuid[11],
             uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

