std::string Board::GetSystemInfoJson() {
    cJSON *root = cJSON_CreateObject();

    // Hardware information
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    cJSON *hardware = cJSON_CreateObject();
    cJSON_AddItemToObject(root, "hardware", hardware);

    // Chip model
    const char* chip_model;
    switch (chip_info.model) {
        case CHIP_ESP32: chip_model = "ESP32"; break;
        case CHIP_ESP32S2: chip_model = "ESP32-S2"; break;
        case CHIP_ESP32S3: chip_model = "ESP32-S3"; break;
        case CHIP_ESP32C3: chip_model = "ESP32-C3"; break;
        case CHIP_ESP32H2: chip_model = "ESP32-H2"; break;
        case CHIP_ESP32C2: chip_model = "ESP32-C2"; break;
        case CHIP_ESP32C6: chip_model = "ESP32-C6"; break;
        default: chip_model = "Unknown";
    }
    cJSON_AddStringToObject(hardware, "chipModel", chip_model);

    // Flash size
    cJSON_AddNumberToObject(hardware, "flashSize", spi_flash_get_chip_size());

    // MAC address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(hardware, "macAddress", mac_str);

    // CPU cores and features
    cJSON_AddNumberToObject(hardware, "cpuCores", chip_info.cores);
    cJSON_AddNumberToObject(hardware, "revision", chip_info.revision);

    // Application metadata
    cJSON *app = cJSON_CreateObject();
    cJSON_AddItemToObject(root, "application", app);

    // Get running partition info
    const esp_partition_t* running = esp_ota_get_running_partition();
    if (running) {
        cJSON_AddStringToObject(app, "partitionName", running->label);
    }

    // Compile time info
    cJSON_AddStringToObject(app, "compileTime", __DATE__ " " __TIME__);

    // Project name and version would typically come from build system
    // For now we'll add placeholders - in a real implementation these
    // would come from Kconfig or cmake variables
    cJSON_AddStringToObject(app, "name", "xiaozhi-esp32");
    cJSON_AddStringToObject(app, "version", "1.0.0");

    // Runtime information
    cJSON *runtime = cJSON_CreateObject();
    cJSON_AddItemToObject(root, "runtime", runtime);

    // Heap information
    cJSON_AddNumberToObject(runtime, "freeHeap", esp_get_free_heap_size());
    cJSON_AddNumberToObject(runtime, "minimumFreeHeap", esp_get_minimum_free_heap_size());

    // UUID
    cJSON_AddStringToObject(runtime, "uuid", GetUuid().c_str());

    // Partition table information
    cJSON *partitions = cJSON_CreateArray();
    cJSON_AddItemToObject(root, "partitions", partitions);

    // Iterate through partitions
    esp_partition_iterator_t it = esp_partition_find(ESP_PARTITION_TYPE_APP, ESP_PARTITION_SUBTYPE_ANY, NULL);
    while (it != NULL) {
        const esp_partition_t* partition = esp_partition_get(it);
        cJSON *partition_obj = cJSON_CreateObject();
        cJSON_AddStringToObject(partition_obj, "label", partition->label);
        cJSON_AddStringToObject(partition_obj, "type", 
            partition->type == ESP_PARTITION_TYPE_APP ? "app" : 
            partition->type == ESP_PARTITION_TYPE_DATA ? "data" : "unknown");
        cJSON_AddNumberToObject(partition_obj, "address", partition->address);
        cJSON_AddNumberToObject(partition_obj, "size", partition->size);
        cJSON_AddItemToArray(partitions, partition_obj);
        it = esp_partition_next(it);
    }
    esp_partition_iterator_release(it);

    // Add data partitions
    it = esp_partition_find(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_ANY, NULL);
    while (it != NULL) {
        const esp_partition_t* partition = esp_partition_get(it);
        cJSON *partition_obj = cJSON_CreateObject();
        cJSON_AddStringToObject(partition_obj, "label", partition->label);
        cJSON_AddStringToObject(partition_obj, "type", "data");
        cJSON_AddNumberToObject(partition_obj, "address", partition->address);
        cJSON_AddNumberToObject(partition_obj, "size", partition->size);
        cJSON_AddItemToArray(partitions, partition_obj);
        it = esp_partition_next(it);
    }
    esp_partition_iterator_release(it);

    // Convert to string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string);
    cJSON_free(json_string);
    cJSON_Delete(root);

    return result;
}

