Button::Button(gpio_num_t gpio_num, bool active_high, uint16_t long_press_time,
               uint16_t short_press_time, bool enable_power_save)
    : gpio_num_(gpio_num) {

    button_config_t cfg = {
        .type = BUTTON_TYPE_GPIO,
        .gpio_button_config = {
            .gpio_num = gpio_num,
            .active_level = active_high ? 1 : 0,
        }
    };

    button_handle_ = iot_button_create(&cfg);
    if (!button_handle_) {
        ESP_LOGE(TAG, "Failed to create button on GPIO %d", gpio_num);
        return;
    }

    // Configure press times if valid values are given
    if (long_press_time > 0) {
        iot_button_set_long_press_time(button_handle_, long_press_time);
    }

    if (short_press_time > 0) {
        iot_button_set_short_press_time(button_handle_, short_press_time);
    }

    if (enable_power_save) {
        iot_button_enable_power_save(button_handle_);
    }
}

