void Button::OnPressUp(std::function<void()> callback) {
    if (button_handle_ == nullptr) {
        return;
    }

    on_press_up_ = std::move(callback);

    // Register the callback with the underlying button driver
    iot_button_register_cb(button_handle_, BUTTON_PRESS_UP, [](void* arg, void* usr_data) {
        Button* btn = static_cast<Button*>(usr_data);
        if (btn->on_press_up_) {
            btn->on_press_up_();
        }
    }, this);
}

