void Button::OnClick(std::function<void()> callback) {
    on_click_ = std::move(callback);

    if (button_handle_ == nullptr) {
        ESP_LOGE(TAG, "Button handle is null");
        return;
    }

    // Register the callback with the IoT button library for single click events
    esp_err_t err = iot_button_register_cb(button_handle_, BUTTON_SINGLE_CLICK, 
        [](void* arg) {
            Button* btn = static_cast<Button*>(arg);
            if (btn && btn->on_click_) {
                btn->on_click_();
