void Button::OnDoubleClick(std::function<void()> callback) {
    if (button_handle_ == nullptr) {
        ESP_LOGE(TAG, "Button handle is invalid");
        return;
    }

    // Store the callback
    on_double_click_ = std::move(callback);

    // Register the double click event with the button driver
    // Using BUTTON_DOUBLE_CLICK event type
    button_event_register(button_handle_, BUTTON_DOUBLE_CLICK, [](void* arg) {
        Button* btn = static_cast<Button*>(arg);
        if (btn->on_double_click_) {
            btn->on_double_click_();
        }
    }, this);
}

