void Button::OnMultipleClick(std::function<void()> callback, uint8_t click_count) {
    on_multiple_click_ = callback;

    if (button_handle_ != nullptr) {
        // Register the multiple click event with the IoT button driver
        // The click_count parameter specifies how many consecutive clicks to detect
        iot_button_set_evt_cb(button_handle_, BUTTON_MULTIPLE_CLICK, 
            [](void* arg, void* usr_data) {
                Button* btn = static_cast<Button*>(usr_data);
                if (btn->on_multiple_click_) {
                    btn->on_multiple_click_();
                }
            }, this);

        // Set the required click count for the multiple click event
