void WifiBoard::StartNetwork() {
    ESP_LOGI(TAG, "Starting network connection");

    // Initialize WiFi manager with SSID prefix and language
    const char* ssid_prefix = "XIAOZHI_";
    const char* language = GetCurrentLanguageCode(); // Assuming this function exists

    // Set up unified event callback for WiFi events
    auto event_callback = [](void* ctx, int event_type, void* event_data) {
        WifiBoard* board = static_cast<WifiBoard*>(ctx);
        std::string data = "";

        switch(event_type) {
            case WIFI_EVENT_SCANNING:
                board->OnNetworkEvent(NetworkEvent::Scanning);
                break;
            case WIFI_EVENT_CONNECTING:
                if (event_data) {
                    data = static_cast<const char*>(event_data);
                }
                board->OnNetworkEvent(NetworkEvent::Connecting, data);
                break;
            case WIFI_EVENT_CONNECTED:
                if (event_data) {
                    data = static_cast<const char*>(event_data);
                }
                board->OnNetworkEvent(NetworkEvent::Connected, data);
                break;
            case WIFI_EVENT_DISCONNECTED:
                board->OnNetworkEvent(NetworkEvent::Disconnected);
                break;
            case WIFI_EVENT_CONFIG_MODE_ENTER:
                board->OnNetworkEvent(NetworkEvent::ConfigModeEnter);
                break;
            case WIFI_EVENT_CONFIG_MODE_EXIT:
                board->OnNetworkEvent(NetworkEvent::ConfigModeExit);
                break;
            default:
                break;
        }
    };

    // Initialize WiFi manager (assuming this function exists based on common patterns)
    wifi_manager_config_t config = {};
    config.ssid_prefix = ssid_prefix;
    config.language = language;
    config.event_callback = event_callback;
    config.callback_ctx = this;

    // Attempt to initialize WiFi manager
    esp_err_t err = wifi_manager_init(&config);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize WiFi manager: %s", esp_err_to_name(err));
        return;
    }

    // Try to establish WiFi connection
    TryWifiConnect();

    // If connection fails, enter configuration mode
    // This logic would typically be handled by the WiFi manager internally
    // but we ensure config mode is available as fallback
}

