void WifiBoard::TryWifiConnect()
{
    // Check if we have stored SSID credentials
    if (SsidManager::GetInstance().HasSavedSsid()) {
        ESP_LOGI(TAG, "Attempting to connect to saved WiFi network");

        // Reset any previous connection state
        in_config_mode_ = false;

        // Start WiFi station connection
        WifiStation::GetInstance().Connect();

        // Start connection timeout timer
        esp_timer_create_args_t timer_args = {};
        timer_args.callback = OnWifiConnectTimeout;
        timer_args.arg = this;
        timer_args.name = "wifi_connect_timeout";

        if (connect_timer_) {
            esp_timer_stop(connect_timer_);
            esp_timer_delete(connect_timer_);
        }

        esp_timer_create(&timer_args, &connect_timer_);
        esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
    } else {
        ESP_LOGI(TAG, "No saved WiFi credentials found, starting config mode");

        // Brief delay before entering config mode
        vTaskDelay(pdMS_TO_TICKS(1000));

        // Enter WiFi configuration mode
        StartWifiConfigMode();
    }
}

