void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string& data) {
    switch (event) {
        case NetworkEvent::Scanning:
            // Handle scanning event
            ESP_LOGI(TAG, "Network scanning");
            break;

        case NetworkEvent::Connecting:
            // Handle connecting event
            ESP_LOGI(TAG, "Connecting to network: %s", data.c_str());
            // Start connection timer if not already running
            if (connect_timer_ != nullptr) {
                esp_timer_stop(connect_timer_);
                esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000);
            }
            break;

        case NetworkEvent::Connected:
            // Handle connected event
            ESP_LOGI(TAG, "Network connected: %s", data.c_str());
            // Stop connection timer
            if (connect_timer_ != nullptr) {
                esp_timer_stop(connect_timer_);
            }
            // Release provisioning resources if in config mode
            if (in_config_mode_) {
                in_config_mode_ = false;
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
                // Clean up Blufi provisioning if used
                blufi_cleanup();
#endif
            }
            break;

        case NetworkEvent::Disconnected:
            // Handle disconnected event
            ESP_LOGI(TAG, "Network disconnected");
            // Stop connection timer
            if (connect_timer_ != nullptr) {
                esp_timer_stop(connect_timer_);
            }
            break;

        case NetworkEvent::ConfigModeEntered:
            // Handle config mode entered
            ESP_LOGI(TAG, "Entered configuration mode");
            in_config_mode_ = true;
            break;

        case NetworkEvent::ConfigModeExited:
            // Handle config mode exited
            ESP_LOGI(TAG, "Exited configuration mode");
            in_config_mode_ = false;
            // Attempt to reconnect to WiFi
            TryWifiConnect();
            break;

        default:
            ESP_LOGW(TAG, "Unhandled network event: %d", static_cast<int>(event));
            break;
    }

    // Notify external callback if set
    if (network_event_callback_) {
        network_event_callback_(event, data);
    }
}

