void WifiBoard::OnWifiConnectTimeout(void* arg) {
    WifiBoard* board = static_cast<WifiBoard*>(arg);
    if (!board) {
        ESP_LOGE(TAG, "Invalid argument to OnWifiConnectTimeout");
        return;
    }

    ESP_LOGW(TAG, "WiFi connection timed out after %d seconds", CONNECT_TIMEOUT_SEC);

    // Disconnect current station attempt
    wifi_station_disconnect();

    // Stop and delete the connection timer
    if (board->connect_timer_) {
        esp_timer_stop(board->connect_timer_);
        esp_timer_delete(board->connect_timer_);
        board->connect_timer_ = nullptr;
    }

    // Enter WiFi configuration mode to allow user reconfiguration
    board->StartWifiConfigMode();
}

