void WifiBoard::StartWifiConfigMode() {
    // Set the device state to configuring mode
    in_config_mode_ = true;

    // Get display for user feedback
    auto disp = Board::GetInstance().GetDisplay();

    // Stop any existing network connections
    auto& wifi_manager = WifiManager::GetInstance();
    if (wifi_manager.IsInitialized()) {
        wifi_manager.Stop();
    }

    // Enable provisioning method based on compile-time flags
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Bluetooth Low Energy provisioning via Blufi
    ESP_LOGI(TAG, "Starting WiFi configuration mode via Blufi");
    if (disp) {
        disp->ShowMessage(ICON_FA_BLUETOOTH " " LANG_CONFIG.CONNECT_TO_HOTSPOT "Blufi", 0);
    }

    // Initialize and start Blufi
    auto& blufi = Blufi::GetInstance();
    esp_err_t ret = blufi.init();
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize Blufi: %s", esp_err_to_name(ret));
        if (disp) {
            disp->ShowMessage(ICON_FA_EXCLAMATION_TRIANGLE " Blufi Init Failed", 3000);
        }
        return;
    }

#elif defined(CONFIG_WIFI_PROVISIONING_AFSK)
    // Acoustic provisioning through audio input
    ESP_LOGI(TAG, "Starting WiFi configuration mode via AFSK");
    if (disp) {
        disp->ShowMessage(ICON_FA_VOLUME_UP " " LANG_CONFIG.CONNECT_TO_HOTSPOT "AFSK", 0);
    }

    // Initialize AFSK demodulator
    afsk_demod_init();

#else
    // Default to hotspot-based configuration with user prompts
    ESP_LOGI(TAG, "Starting WiFi configuration mode via SoftAP");

    // Start SoftAP for configuration
    wifi_manager.StartAccessPoint();

    // Display connection instructions
    if (disp) {
        std::string ap_ssid = SystemInfo::GetApSsid();
        disp->ShowMessage(ICON_FA_WIFI " " LANG_CONFIG.CONNECT_TO_HOTSPOT + ap_ssid, 0);
    }
#endif

    // Notify about network state change
    if (network_event_callback_) {
        network_event_callback_(NetworkEvent::ConfigurationStarted, "");
    }
}

