void WifiBoard::EnterWifiConfigMode() {
    // Prevent multiple entries into config mode
    if (in_config_mode_) {
        ESP_LOGW(TAG, "Already in Wi-Fi config mode");
        return;
    }

    ESP_LOGI(TAG, "Entering Wi-Fi configuration mode");

    // Mark that we're now in config mode
    in_config_mode_ = true;

    // Gracefully stop ongoing network activity or audio processing
    Application::GetInstance().StopActiveProcesses();

    // Get display instance and show notification
    auto disp = Board::GetInstance().GetDisplay();
    if (disp) {
        disp->Clear();
        disp->DrawString(ICON_FA_WIFI, 0, 10, FontSize::LARGE);
        disp->DrawString(_("Entering Wi-Fi Config Mode"), 0, 40, FontSize::MEDIUM);
        disp->Display();
    }

    // Reset any existing Wi-Fi connections or attempts
    WifiStation::Disconnect();

    // Begin the actual configuration process (provisioning)
    StartWifiConfigMode();
}

