const char* WifiBoard::GetNetworkStateIcon() {
    // Check if in WiFi configuration mode
    if (in_config_mode_) {
        return FONT_AWESOME_COG;
    }

    // Check WiFi connection status
    wifi_manager_stat_e wifi_status = wifi_manager_get_status();

    // If not connected or connecting, show signal off
    if (wifi_status != WIFI_MANAGER_STA_CONNECTED) {
        return FONT_AWESOME_SIGNAL_OFF;
    }

    // Get RSSI value for signal strength
    int rssi = wifi_station_get_rssi();

    // Return appropriate icon based on RSSI value
    if (rssi == -127 || rssi <= -90) {
        // Very weak signal or invalid RSSI
        return FONT_AWESOME_SIGNAL_WEAK;
    } else if (rssi <= -70) {
        // Weak signal
        return FONT_AWESOME_SIGNAL_FAIR;
    } else if (rssi <= -50) {
        // Good signal
        return FONT_AWESOME_SIGNAL_GOOD;
    } else {
        // Strong signal
        return FONT_AWESOME_SIGNAL_STRONG;
    }
}

