void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level) {
    wifi_ps_type_t ps_type;

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            ps_type = WIFI_PS_MAX_MODEM;
            break;
        case PowerSaveLevel::BALANCED:
            ps_type = WIFI_PS_MIN_MODEM;
            break;
        case PowerSaveLevel::PERFORMANCE:
            ps_type = WIFI_PS_NONE;
            break;
        default:
            ESP_LOGW(TAG, "Unknown PowerSaveLevel: %d", static_cast<int>(level));
            return;
    }

    esp_err_t err = esp_wifi_set_ps(ps_type);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set Wi-Fi power save mode: %s", esp_err_to_name(err));
    } else {
        ESP_LOGI(TAG, "Wi-Fi power save level set to %d", static_cast<int>(ps_type));
    }
}

