502: void LcdDisplay::SetChatMessage(const char* role, const char* content) {
503:     DisplayLockGuard lock(this);
504:     if (content_ == nullptr) {
505:         return;
506:     }
507:     
508:     // Check if message count exceeds limit
509:     uint32_t child_count = lv_obj_get_child_cnt(content_);
510:     if (child_count >= MAX_MESSAGES) {
511:         // Delete the oldest message (first child object)
512:         lv_obj_t* first_child = lv_obj_get_child(content_, 0);
513:         lv_obj_t* last_child = lv_obj_get_child(content_, child_count - 1);
514:         if (first_child != nullptr) {
515:             lv_obj_del(first_child);
516:         }
517:         // Scroll to the last message immediately
518:         if (last_child != nullptr) {
519:             lv_obj_scroll_to_view_recursive(last_child, LV_ANIM_OFF);
520:         }
521:     }
522:     
523:     // Collapse system messages (if it's a system message, check if the last message is also a system message)
524:     if (strcmp(role, "system") == 0) {
525:         if (child_count > 0) {
526:             // Get the last message container
527:             lv_obj_t* last_container = lv_obj_get_child(content_, child_count - 1);
528:             if (last_container != nullptr && lv_obj_get_child_cnt(last_container) > 0) {
529:                 // Get the bubble inside the container
530:                 lv_obj_t* last_bubble = lv_obj_get_child(last_container, 0);
531:                 if (last_bubble != nullptr) {
532:                     // Check if bubble type is system message
533:                     void* bubble_type_ptr = lv_obj_get_user_data(last_bubble);
534:                     if (bubble_type_ptr != nullptr && strcmp((const char*)bubble_type_ptr, "system") == 0) {
535:                         // If the last message is also a system message, delete it
536:                         lv_obj_del(last_container);
537:                     }
538:                 }
539:             }
540:         }
541:     } else {
542:         // Hide the centered AI logo
543:         lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
544:     }
545: 
546:     // Avoid empty message boxes
547:     if(strlen(content) == 0) {
548:         return;
549:     }
550: 
551:     auto lvgl_theme = static_cast<LvglTheme*>(current_theme_);
552:     auto text_font = lvgl_theme->text_font()->font();
553: 
554:     // Create a message bubble
555:     lv_obj_t* msg_bubble = lv_obj_create(content_);
556:     lv_obj_set_style_radius(msg_bubble, 8, 0);
557:     lv_obj_set_scrollbar_mode(msg_bubble, LV_SCROLLBAR_MODE_OFF);
558:     lv_obj_set_style_border_width(msg_bubble, 0, 0);
559:     lv_obj_set_style_pad_all(msg_bubble, lvgl_theme->spacing(4), 0);
560: 
561:     // Create the message text
562:     lv_obj_t* msg_text = lv_label_create(msg_bubble);
563:     lv_label_set_text(msg_text, content);
564:     
565:     // Calculate actual text width
566:     lv_coord_t text_width = lv_txt_get_width(content, strlen(content), text_font, 0);
567: 
568:     // Calculate bubble width
569:     lv_coord_t max_width = LV_HOR_RES * 85 / 100 - 16;  // 85% of screen width
570:     lv_coord_t min_width = 20;  
571:     lv_coord_t bubble_width;
572:     
573:     // Ensure text width is not less than minimum width
574:     if (text_width < min_width) {
575:         text_width = min_width;
576:     }
577: 
578:     // If text width is less than max width, use text width
579:     if (text_width < max_width) {
580:         bubble_width = text_width; 
581:     } else {
582:         bubble_width = max_width;
583:     }
584:     
585:     // Set message text width
586:     lv_obj_set_width(msg_text, bubble_width);  // Subtract padding
587:     lv_label_set_long_mode(msg_text, LV_LABEL_LONG_WRAP);
588: 
589:     // Set bubble width
590:     lv_obj_set_width(msg_bubble, bubble_width);
591:     lv_obj_set_height(msg_bubble, LV_SIZE_CONTENT);
592: 
593:     // Set alignment and style based on message role
594:     if (strcmp(role, "user") == 0) {
595:         // User messages are right-aligned with green background
596:         lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->user_bubble_color(), 0);
597:         lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
598:         // Set text color for contrast
599:         lv_obj_set_style_text_color(msg_text, lvgl_theme->text_color(), 0);
600:         
601:         // Set custom attribute to mark bubble type
602:         lv_obj_set_user_data(msg_bubble, (void*)"user");
603:         
604:         // Set appropriate width for content
605:         lv_obj_set_width(msg_bubble, LV_SIZE_CONTENT);
606:         lv_obj_set_height(msg_bubble, LV_SIZE_CONTENT);
607:         
608:         // Don't grow
609:         lv_obj_set_style_flex_grow(msg_bubble, 0, 0);
610:     } else if (strcmp(role, "assistant") == 0) {
611:         // Assistant messages are left-aligned with white background
612:         lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->assistant_bubble_color(), 0);
613:         lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
614:         // Set text color for contrast
615:         lv_obj_set_style_text_color(msg_text, lvgl_theme->text_color(), 0);
616:         
617:         // Set custom attribute to mark bubble type
618:         lv_obj_set_user_data(msg_bubble, (void*)"assistant");
619:         
620:         // Set appropriate width for content
621:         lv_obj_set_width(msg_bubble, LV_SIZE_CONTENT);
622:         lv_obj_set_height(msg_bubble, LV_SIZE_CONTENT);
623:         
624:         // Don't grow
625:         lv_obj_set_style_flex_grow(msg_bubble, 0, 0);
626:     } else if (strcmp(role, "system") == 0) {
627:         // System messages are center-aligned with light gray background
628:         lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->system_bubble_color(), 0);
629:         lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
630:         // Set text color for contrast
631:         lv_obj_set_style_text_color(msg_text, lvgl_theme->system_text_color(), 0);
632:         
633:         // Set custom attribute to mark bubble type
634:         lv_obj_set_user_data(msg_bubble, (void*)"system");
635:         
636:         // Set appropriate width for content
637:         lv_obj_set_width(msg_bubble, LV_SIZE_CONTENT);
638:         lv_obj_set_height(msg_bubble, LV_SIZE_CONTENT);
639:         
640:         // Don't grow
641:         lv_obj_set_style_flex_grow(msg_bubble, 0, 0);
642:     }
643:     
644:     // Create a full-width container for user messages to ensure right alignment
645:     if (strcmp(role, "user") == 0) {
646:         // Create a full-width container
647:         lv_obj_t* container = lv_obj_create(content_);
648:         lv_obj_set_width(container, LV_HOR_RES);
649:         lv_obj_set_height(container, LV_SIZE_CONTENT);
650:         
651:         // Make container transparent and borderless
652:         lv_obj_set_style_bg_opa(container, LV_OPA_TRANSP, 0);
653:         lv_obj_set_style_border_width(container, 0, 0);
654:         lv_obj_set_style_pad_all(container, 0, 0);
655:         
656:         // Move the message bubble into this container
657:         lv_obj_set_parent(msg_bubble, container);
658:         
659:         // Right align the bubble in the container
660:         lv_obj_align(msg_bubble, LV_ALIGN_RIGHT_MID, -25, 0);
661:         
662:         // Auto-scroll to this container
663:         lv_obj_scroll_to_view_recursive(container, LV_ANIM_ON);
664:     } else if (strcmp(role, "system") == 0) {
665:         // Create full-width container for system messages to ensure center alignment
666:         lv_obj_t* container = lv_obj_create(content_);
667:         lv_obj_set_width(container, LV_HOR_RES);
668:         lv_obj_set_height(container, LV_SIZE_CONTENT);
669:         
670:         lv_obj_set_style_bg_opa(container, LV_OPA_TRANSP, 0);
671:         lv_obj_set_style_border_width(container, 0, 0);
672:         lv_obj_set_style_pad_all(container, 0, 0);
673:         
674:         lv_obj_set_parent(msg_bubble, container);
675:         lv_obj_align(msg_bubble, LV_ALIGN_CENTER, 0, 0);
676:         lv_obj_scroll_to_view_recursive(container, LV_ANIM_ON);
677:     } else {
678:         // For assistant messages
679:         // Left align assistant messages
680:         lv_obj_align(msg_bubble, LV_ALIGN_LEFT_MID, 0, 0);
681: 
682:         // Auto-scroll to the message bubble
683:         lv_obj_scroll_to_view_recursive(msg_bubble, LV_ANIM_ON);
684:     }
685:     
686:     // Store reference to the latest message label
687:     chat_message_label_ = msg_text;
688: }
