690: void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image) {
691:     DisplayLockGuard lock(this);
692:     if (content_ == nullptr) {
693:         return;
694:     }
695: 
696:     if (image == nullptr) {
697:         return;
698:     }
699:     
700:     auto lvgl_theme = static_cast<LvglTheme*>(current_theme_);
701:     // Create a message bubble for image preview
702:     lv_obj_t* img_bubble = lv_obj_create(content_);
703:     lv_obj_set_style_radius(img_bubble, 8, 0);
704:     lv_obj_set_scrollbar_mode(img_bubble, LV_SCROLLBAR_MODE_OFF);
705:     lv_obj_set_style_border_width(img_bubble, 0, 0);
706:     lv_obj_set_style_pad_all(img_bubble, lvgl_theme->spacing(4), 0);
707:     
708:     // Set image bubble background color (similar to system message)
709:     lv_obj_set_style_bg_color(img_bubble, lvgl_theme->assistant_bubble_color(), 0);
710:     lv_obj_set_style_bg_opa(img_bubble, LV_OPA_70, 0);
711:     
712:     // Set custom attribute to mark bubble type
713:     lv_obj_set_user_data(img_bubble, (void*)"image");
714: 
715:     // Create the image object inside the bubble
716:     lv_obj_t* preview_image = lv_image_create(img_bubble);
717:     
718:     // Calculate appropriate size for the image
719:     lv_coord_t max_width = LV_HOR_RES * 70 / 100;  // 70% of screen width
720:     lv_coord_t max_height = LV_VER_RES * 50 / 100; // 50% of screen height
721:     
722:     // Calculate zoom factor to fit within maximum dimensions
723:     auto img_dsc = image->image_dsc();
724:     lv_coord_t img_width = img_dsc->header.w;
725:     lv_coord_t img_height = img_dsc->header.h;
726:     if (img_width == 0 || img_height == 0) {
727:         img_width = max_width;
728:         img_height = max_height;
729:         ESP_LOGW(TAG, "Invalid image dimensions: %ld x %ld, using default dimensions: %ld x %ld", img_width, img_height, max_width, max_height);
730:     }
731:     
732:     lv_coord_t zoom_w = (max_width * 256) / img_width;
733:     lv_coord_t zoom_h = (max_height * 256) / img_height;
734:     lv_coord_t zoom = (zoom_w < zoom_h) ? zoom_w : zoom_h;
735:     
736:     // Ensure zoom doesn't exceed 256 (100%)
737:     if (zoom > 256) zoom = 256;
738:     
739:     // Set image properties
740:     lv_image_set_src(preview_image, img_dsc);
741:     lv_image_set_scale(preview_image, zoom);
742:     
743:     // Add event handler to clean up LvglImage when image is deleted
744:     // We need to transfer ownership of the unique_ptr to the event callback
745:     LvglImage* raw_image = image.release(); // Release ownership of smart pointer
746:     lv_obj_add_event_cb(preview_image, [](lv_event_t* e) {
747:         LvglImage* img = (LvglImage*)lv_event_get_user_data(e);
748:         if (img != nullptr) {
749:             delete img; // Properly release memory by deleting LvglImage object
750:         }
751:     }, LV_EVENT_DELETE, (void*)raw_image);
752:     
753:     // Calculate actual scaled image dimensions
754:     lv_coord_t scaled_width = (img_width * zoom) / 256;
755:     lv_coord_t scaled_height = (img_height * zoom) / 256;
756:     
757:     // Set bubble size to be 16 pixels larger than the image (8 pixels on each side)
758:     lv_obj_set_width(img_bubble, scaled_width + 16);
759:     lv_obj_set_height(img_bubble, scaled_height + 16);
760:     
761:     // Don't grow in flex layout
762:     lv_obj_set_style_flex_grow(img_bubble, 0, 0);
763:     
764:     // Center the image within the bubble
765:     lv_obj_center(preview_image);
766:     
767:     // Left align the image bubble like assistant messages
768:     lv_obj_align(img_bubble, LV_ALIGN_LEFT_MID, 0, 0);
769: 
770:     // Auto-scroll to the image bubble
771:     lv_obj_scroll_to_view_recursive(img_bubble, LV_ANIM_ON);
772: }
