void SingleLed::StartBlinkTask(int times, int interval_ms)
{
    // Check if LED strip is initialized, exit early if not
    if (led_strip_ == nullptr) {
        ESP_LOGW(TAG, "LED strip not initialized, skipping blink task");
        return;
        }

    // Stop any existing timer
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
    }

    // Set the blink parameters
    blink_counter_ = times;
    blink_interval_ms_ = interval_ms;

    // If times is 0, just stop the blinking
    if (times == 0) {
        return;
    }

    // Create timer if it doesn't exist
    if (blink_timer_ == nullptr) {
        esp_timer_create_args_t timer_args = {
            .callback = [](void* arg) {
                auto led = static_cast<SingleLed*>(arg);
                led->OnBlinkTimer();
            },
            .arg = this,
            .dispatch_method = ESP_TIMER_TASK,
            .name = "single_led_blink_timer"
        };
        ESP_ERROR_CHECK(esp_timer_create(&timer_args, &blink_timer_));
    }

    // Start the timer with the specified interval
    ESP_ERROR_CHECK(esp_timer_start_periodic(blink_timer_, interval_ms * 1000));
}

