    // Toggle LED state: assuming even numbers mean "off" and odd/on mean "on"
    static bool is_on = false;

    if (is_on) {
        TurnOff();
        is_on = false;
    } else {
        TurnOn();
        is_on = true;
    }

    // Update blink counter only if not infinite blinking
    if (blink_counter_ != BLINK_INFINITE) {
        blink_counter_--;
    }

    // Apply LED changes to hardware
    if (led_strip_) {
        led_strip_flush(led_strip_);
    }
