void SingleLed::OnStateChanged() {
    auto& app = Application::GetInstance();
    auto device_state = app.GetDeviceState();

    std::lock_guard<std::mutex> lock(mutex_);

    switch (device_state) {
        case kDeviceStateStarting:
            SetColor(0, 0, DEFAULT_BRIGHTNESS);  // Blue
            StartContinuousBlink(100);
            break;

        case kDeviceStateWifiConfiguring:
            SetColor(0, 0, DEFAULT_BRIGHTNESS);  // Blue
            StartContinuousBlink(500);
            break;

        case kDeviceStateIdle:
            SetColor(0, DEFAULT_BRIGHTNESS, 0);  // Green
            TurnOn();
            break;

        case kDeviceStateConnecting:
            SetColor(DEFAULT_BRIGHTNESS, DEFAULT_BRIGHTNESS, 0);  // Yellow
            TurnOn();
            break;

        case kDeviceStateListening:
        case kDeviceStateAudioTesting:
            if (app.IsVoiceDetected()) {
                SetColor(HIGH_BRIGHTNESS, 0, 0);  // Red (bright)
            } else {
                SetColor(LOW_BRIGHTNESS, 0, 0);   // Red (dim)
            }
            StartContinuousBlink(200);  // Pulse effect
            break;

        case kDeviceStateSpeaking:
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, HIGH_BRIGHTNESS);  // White
            TurnOn();
            break;

        case kDeviceStateUpgrading:
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, 0);  // Yellow
            StartContinuousBlink(100);
            break;

        case kDeviceStateActivating:
            SetColor(0, HIGH_BRIGHTNESS, HIGH_BRIGHTNESS);  // Cyan
            StartContinuousBlink(500);
            break;

        case kDeviceStateFatalError:
            SetColor(HIGH_BRIGHTNESS, 0, 0);  // Red
            StartContinuousBlink(250);
            break;

        default:
        case kDeviceStateUnknown:
            ESP_LOGW(TAG, "Unknown device state: %d", device_state);
            TurnOff();
            break;
    }
}

