MqttProtocol::MqttProtocol() {
    // Initialize the event group for synchronization
    event_group_handle_ = xEventGroupCreate();

    // Initialize the reconnect timer
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = [](void* arg) {
        MqttProtocol* protocol = static_cast<MqttProtocol*>(arg);
        if (protocol && protocol->alive_ && *(protocol->alive_)) {
            // Check if we're in an idle state before attempting reconnection
            auto& app = Application::GetInstance();
            if (app.IsIdle()) {
                // Schedule the reconnection attempt through the application's task scheduler
                app.PostTask([protocol]() {
                    if (protocol->alive_ && *(protocol->alive_)) {
                        protocol->StartMqttClient();
                    }
                });
            }
        }
    };
    timer_args.arg = this;
    timer_args.name = "mqtt_reconnect";

