bool MqttProtocol::StartMqttClient(bool report_error) {
    if (!alive_->load()) {
        return false;
    }

    // Get network and settings from board
    auto& board = Board::GetInstance();
    auto network = board.GetNetwork();
    auto settings = board.GetSettings();

    // Check if we have valid network connection
    if (!network || !network->IsConnected()) {
        ESP_LOGE(TAG, "No network connection available");
        if (report_error) {
            // Report error through appropriate channel
            Application::GetInstance().ReportError("No network connection for MQTT");
        }
        return false;
    }

    // Get MQTT configuration from settings
    std::string broker_url = settings->GetMqttBrokerUrl();
    std::string client_id = settings->GetMqttClientId();
    std::string username = settings->GetMqttUsername();
    std::string password = settings->GetMqttPassword();
    std::string subscribe_topic = settings->GetMqttSubscribeTopic();
    publish_topic_ = settings->GetMqttPublishTopic();

    if (broker_url.empty() || client_id.empty()) {
        ESP_LOGE(TAG, "MQTT configuration incomplete");
        if (report_error) {
            Application::GetInstance().ReportError("MQTT configuration incomplete");
        }
        return false;
    }

    // Clean up any existing MQTT client
    if (mqtt_) {
        mqtt_.reset();
    }

    // Create MQTT client configuration
    Mqtt::Config config;
    config.broker_url = broker_url;
    config.client_id = client_id;
    config.username = username;
    config.password = password;
    config.keep_alive = MQTT_PING_INTERVAL_SECONDS;

    // Create and initialize MQTT client
    mqtt_ = std::make_unique<Mqtt>();
    if (!mqtt_->Initialize(config)) {
        ESP_LOGE(TAG, "Failed to initialize MQTT client");
        if (report_error) {
            Application::GetInstance().ReportError("MQTT initialization failed");
        }
        return false;
    }

    // Set up event handlers
    mqtt_->SetConnectionHandler([this](bool connected) {
        if (connected) {
            ESP_LOGI(TAG, "MQTT connected successfully");
            // Subscribe to topic
            auto settings = Board::GetInstance().GetSettings();
            std::string subscribe_topic = settings->GetMqttSubscribeTopic();
            if (!subscribe_topic.empty()) {
                mqtt_->Subscribe(subscribe_topic);
            }

            // Send hello message
            std::string hello_msg = GetHelloMessage();
            if (!hello_msg.empty()) {
                mqtt_->Publish(publish_topic_, hello_msg);
            }

            // Set event bit for successful connection
            if (event_group_handle_) {
                xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
            }
        } else {
            ESP_LOGW(TAG, "MQTT disconnected");
            // Schedule reconnection
            ScheduleReconnect();
        }
    });

    mqtt_->SetMessageHandler([this](const std::string& topic, const std::string& payload) {
        ESP_LOGD(TAG, "MQTT message received on topic: %s", topic.c_str());

        // Parse JSON payload
        cJSON* root = cJSON_Parse(payload.c_str());
        if (root) {
            // Check message type
            cJSON* type_obj = cJSON_GetObjectItem(root, "type");
            if (type_obj && cJSON_IsString(type_obj)) {
                std::string msg_type = type_obj->valuestring;

                if (msg_type == "server_hello") {
                    ParseServerHello(root);
                } else if (msg_type == "open_audio_channel") {
                    OpenAudioChannel();
                } else if (msg_type == "close_audio_channel") {
                    CloseAudioChannel();
                } else {
                    ESP_LOGD(TAG, "Unknown message type: %s", msg_type.c_str());
                }
            }
            cJSON_Delete(root);
        } else {
            ESP_LOGW(TAG, "Failed to parse JSON payload");
        }
    });

    // Start MQTT client
    if (!mqtt_->Start()) {
        ESP_LOGE(TAG, "Failed to start MQTT client");
        if (report_error) {
            Application::GetInstance().ReportError("MQTT start failed");
        }
        return false;
    }

    ESP_LOGI(TAG, "MQTT client started successfully");
    return true;
}

// Helper function to schedule reconnection
void MqttProtocol::ScheduleReconnect() {
    if (!alive_->load()) {
        return;
    }

    // Cancel any existing timer
    if (reconnect_timer_) {
        esp_timer_stop(reconnect_timer_);
    } else {
        // Create timer if it doesn't exist
        esp_timer_create_args_t timer_args = {};
        timer_args.callback = [](void* arg) {
            MqttProtocol* protocol = static_cast<MqttProtocol*>(arg);
            if (protocol && protocol->alive_->load()) {
                protocol->StartMqttClient(true);
            }
        };
        timer_args.arg = this;
        timer_args.name = "mqtt_reconnect";
        esp_timer_create(&timer_args, &reconnect_timer_);
    }

    // Start timer for reconnection
    esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
}

