bool MqttProtocol::SendText(const std::string& text) {
    if (!mqtt_ || publish_topic_.empty()) {
        ESP_LOGE(TAG, "MQTT client not initialized or publish topic not set");
        Application::SetServerError(true);
        return false;
    }

    // Attempt to publish the text message to the predefined topic
    int ret = mqtt_->publish(publish_topic_, text);

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to publish message to topic '%s', error code: %d", publish_topic_.c_str(), ret);
        Application::SetServerError(true);
        return false;
    }

    ESP_LOGD(TAG, "Successfully published message to topic '%s'", publish_topic_.c_str());
    return true;
}

