bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    if (!packet || packet->payload.empty()) {
        ESP_LOGE(TAG, "Invalid audio packet");
        return false;
    }

    // Ensure thread-safe access to UDP channel
    std::lock_guard<std::mutex> lock(channel_mutex_);

    if (!udp_ || !IsAudioChannelOpened()) {
        ESP_LOGE(TAG, "UDP channel not available");
        return false;
    }

    // Generate dynamic nonce using packet size, timestamp, and sequence number
    uint32_t packet_size = static_cast<uint32_t>(packet->payload.size());
    uint64_t timestamp = esp_timer_get_time() / 1000; // milliseconds
    uint32_t sequence_number = local_sequence_++;

    // Create nonce: combine packet size, timestamp, and sequence number
    std::vector<uint8_t> nonce(16, 0); // AES block size
    memcpy(nonce.data(), &packet_size, sizeof(packet_size));
    memcpy(nonce.data() + 4, &timestamp, sizeof(timestamp));
    memcpy(nonce.data() + 12, &sequence_number, sizeof(sequence_number));

    // Update AES nonce
    aes_nonce_.assign(reinterpret_cast<char*>(nonce.data()), nonce.size());

    // Prepare encrypted payload buffer
    std::vector<uint8_t> encrypted_payload(packet->payload.size());

    // Perform AES-CTR encryption
    size_t nc_off = 0;
    unsigned char nonce_counter[16];
    unsigned char stream_block[16];

    memcpy(nonce_counter, nonce.data(), 16);
    memset(stream_block, 0, sizeof(stream_block));

    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, packet->payload.size(), &nc_off, 
                                   nonce_counter, stream_block, 
                                   packet->payload.data(), encrypted_payload.data());

    if (ret != 0) {
        ESP_LOGE(TAG, "AES encryption failed: %d", ret);
        return false;
    }

    // Create binary protocol header (using BinaryProtocol2 format based on structure)
    BinaryProtocol2 header = {};
    header.version = htons(2); // Assuming version 2
    header.type = htons(0); // OPUS type
    header.timestamp = htonl(packet->timestamp);
    header.payload_size = htonl(static_cast<uint32_t>(encrypted_payload.size()));

    // Combine header and encrypted payload
    std::vector<uint8_t> transmit_buffer(sizeof(BinaryProtocol2) + encrypted_payload.size());
    memcpy(transmit_buffer.data(), &header, sizeof(BinaryProtocol2));
    memcpy(transmit_buffer.data() + sizeof(BinaryProtocol2), encrypted_payload.data(), encrypted_payload.size());

    // Send over UDP
    bool success = udp_->Send(transmit_buffer.data(), transmit_buffer.size(), udp_server_, udp_port_);

    if (!success) {
        ESP_LOGE(TAG, "Failed to send audio packet over UDP");
        return false;
    }

    ESP_LOGD(TAG, "Successfully sent audio packet, size: %d, seq: %d", packet_size, sequence_number);
    return true;
}

