void MqttProtocol::CloseAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Only proceed if UDP channel appears to be active
    if (!udp_) {
        ESP_LOGW(TAG, "Attempted to close audio channel, but UDP is not initialized");
        return;
    }

    // Prepare and send a "goodbye" message to notify the server
    const char* goodbye_msg = "{\"type\":\"goodbye\"}";
    ssize_t sent = udp_->Send(goodbye_msg, strlen(goodbye_msg));
    if (sent < 0) {
        ESP_LOGE(TAG, "Failed to send goodbye message over UDP");
    } else {
        ESP_LOGI(TAG, "Sent goodbye message to server (%d bytes)", sent);
    }

    // Close and reset the UDP connection
    udp_.reset();

    ESP_LOGI(TAG, "Audio channel closed successfully");
}

