bool MqttProtocol::OpenAudioChannel() {
    ESP_LOGI(TAG, "Opening audio channel");

    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Check if already opened
    if (IsAudioChannelOpened()) {
        ESP_LOGW(TAG, "Audio channel already opened");
        return true;
    }

    // Ensure MQTT is connected
    if (!mqtt_ || !mqtt_->IsConnected()) {
        ESP_LOGE(TAG, "MQTT not connected");
        return false;
    }

    // Reset sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Send hello message to initiate audio channel
    std::string hello_message = GetHelloMessage();
    if (hello_message.empty()) {
        ESP_LOGE(TAG, "Failed to generate hello message");
        return false;
    }

    if (!SendText(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        return false;
    }

    ESP_LOGI(TAG, "Hello message sent, waiting for server response");

    // Wait for server hello response
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bits on exit
        pdFALSE,  // Wait for any bit
        pdMS_TO_TICKS(10000)  // 10 second timeout
    );

    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT)) {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        return false;
    }

    ESP_LOGI(TAG, "Received server hello response");

    // Validate UDP configuration was received
    if (udp_server_.empty() || udp_port_ <= 0) {
        ESP_LOGE(TAG, "Invalid UDP configuration received from server");
        return false;
    }

    // Initialize UDP connection for audio streaming
    if (!udp_) {
        udp_ = std::make_unique<Udp>();
    }

    if (!udp_->Connect(udp_server_, udp_port_)) {
        ESP_LOGE(TAG, "Failed to connect to UDP server %s:%d", 
                 udp_server_.c_str(), udp_port_);
        return false;
    }

    ESP_LOGI(TAG, "UDP connection established to %s:%d", 
             udp_server_.c_str(), udp_port_);

    // Start UDP receiving task/thread here if needed
    // This would typically involve creating a task that continuously
    // listens for incoming UDP packets, decrypts them, and passes
    // them to a callback

    // For now, we'll assume the UDP listening is handled elsewhere
    // or started by the application layer

    return true;
}

