std::string MqttProtocol::GetHelloMessage() {
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        ESP_LOGE(TAG, "Failed to create JSON root object");
        return "";
    }

    // Set message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add capabilities
    cJSON* capabilities = cJSON_CreateObject();
    if (!capabilities) {
        ESP_LOGE(TAG, "Failed to create capabilities object");
        cJSON_Delete(root);
        return "";
    }
    cJSON_AddBoolToObject(capabilities, "aec", Board::GetInstance().IsAecSupported());
    cJSON_AddBoolToObject(capabilities, "mcp", true); // Assuming always supported; adjust accordingly
    cJSON_AddItemToObject(root, "capabilities", capabilities);

    // Add audio parameters
    cJSON* audio_params = cJSON_CreateObject();
    if (!audio_params) {
        ESP_LOGE(TAG, "Failed to create audio_params object");
        cJSON_Delete(root);
        return "";
    }
    cJSON_AddStringToObject(audio_params, "format", "pcm"); // Or from settings
    cJSON_AddNumberToObject(audio_params, "sample_rate", SETTINGS_DEFAULT_SAMPLE_RATE);
    cJSON_AddNumberToObject(audio_params, "frame_duration_ms", SETTINGS_DEFAULT_FRAME_DURATION_MS);
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Print to string
    char* json_str = cJSON_PrintUnformatted(root);
    if (!json_str) {
        ESP_LOGE(TAG, "Failed to print JSON string");
        cJSON_Delete(root);
        return "";
    }

    std::string result(json_str);
    free(json_str);
    cJSON_Delete(root);

    return result;
}

