void MqttProtocol::ParseServerHello(const cJSON* root) {
    if (!root) {
        ESP_LOGE(TAG, "Invalid server hello message");
        return;
    }

    // Extract UDP server address and port
    cJSON* server_item = cJSON_GetObjectItemCaseSensitive(root, "server");
    cJSON* port_item = cJSON_GetObjectItemCaseSensitive(root, "port");
    if (cJSON_IsString(server_item) && cJSON_IsNumber(port_item)) {
        udp_server_ = std::string(server_item->valuestring);
        udp_port_ = port_item->valueint;
        ESP_LOGI(TAG, "UDP Server: %s:%d", udp_server_.c_str(), udp_port_);
    } else {
        ESP_LOGE(TAG, "Missing or invalid server/port in server hello");
        return;
    }

    // Extract AES key and nonce
    cJSON* key_item = cJSON_GetObjectItemCaseSensitive(root, "key");
    cJSON* nonce_item = cJSON_GetObjectItemCaseSensitive(root, "nonce");
    if (cJSON_IsString(key_item) && cJSON_IsString(nonce_item)) {
        std::string hex_key = key_item->valuestring;
        aes_nonce_ = nonce_item->valuestring;

        std::string decoded_key = DecodeHexString(hex_key);
        if (decoded_key.size() != 16) { // AES-128 expected
            ESP_LOGE(TAG, "Invalid AES key length: %d bytes", decoded_key.size());
            return;
        }

        mbedtls_aes_init(&aes_ctx_);
        int ret = mbedtls_aes_setkey_enc(&aes_ctx_, reinterpret_cast<const unsigned char*>(decoded_key.data()), 128);
        if (ret != 0) {
            ESP_LOGE(TAG, "Failed to set AES key, error: %d", ret);
            return;
        }
        ESP_LOGI(TAG, "AES encryption initialized with provided key");
    } else {
        ESP_LOGE(TAG, "Missing or invalid key/nonce in server hello");
        return;
    }

    // Retrieve audio configuration
    cJSON* sample_rate_item = cJSON_GetObjectItemCaseSensitive(root, "sample_rate");
    cJSON* frame_duration_item = cJSON_GetObjectItemCaseSensitive(root, "frame_duration");
    if (cJSON_IsNumber(sample_rate_item) && cJSON_IsNumber(frame_duration_item)) {
        uint32_t sample_rate = sample_rate_item->valueint;
        uint32_t frame_duration = frame_duration_item->valueint;

        Application& app = Application::GetInstance();
        app.SetSampleRate(sample_rate);
        app.SetFrameDuration(frame_duration);

        ESP_LOGI(TAG, "Audio config updated - Sample Rate: %u Hz, Frame Duration: %u ms",
                 sample_rate, frame_duration);
    } else {
        ESP_LOGW(TAG, "No valid audio configuration found in server hello");
    }

    // Signal that server hello was processed successfully
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

int CharToHex(char c) {
    if (c >= '0' && c <= '9') {
        return c - '0';
    } else if (c >= 'A' && c <= 'F') {
        return c - 'A' + 10;
    } else if (c >= 'a' && c <= 'f') {
        return c - 'a' + 10;
    } else {
        return 0;
    }
}

