void Protocol::SendAbortSpeaking(AbortReason reason)
{
    cJSON *json = cJSON_CreateObject();
    if (!json) {
        ESP_LOGE(TAG, "Failed to create JSON object for abort speaking");
        return;
    }

    cJSON_AddStringToObject(json, "type", "abort_speaking");
    cJSON_AddStringToObject(json, "session_id", session_id_.c_str());

    const char* reason_str = "unknown";
    switch (reason) {
        case kAbortReasonNone:
            reason_str = "none";
            break;
        case kAbortReasonWakeWordDetected:
            reason_str = "wake_word_detected";
            break;
        default:
            reason_str = "unknown";
            break;
    }
    cJSON_AddStringToObject(json, "reason", reason_str);

    char *json_string = cJSON_PrintUnformatted(json);
    if (json_string) {
        SendText(json_string);
        cJSON_free(json_string);
    } else {
        ESP_LOGE(TAG, "Failed to serialize JSON for abort speaking");
    }

    cJSON_Delete(json);
}

