void Protocol::SendStartListening(ListeningMode mode) {
    cJSON* json_root = cJSON_CreateObject();

    // Add sessionId
    cJSON_AddStringToObject(json_root, "sessionId", session_id_.c_str());

    // Add fixed fields
    cJSON_AddStringToObject(json_root, "type", "listen");
    cJSON_AddStringToObject(json_root, "state", "start");

    // Map ListeningMode to string
    const char* mode_str = nullptr;
    switch (mode) {
        case kListeningModeAutoStop:
            mode_str = "auto";
            break;
        case kListeningModeManualStop:
            mode_str = "manual";
            break;
        case kListeningModeRealtime:
            mode_str = "realtime";
            break;
        default:
            mode_str = "unknown"; // Fallback, though ideally shouldn't happen
            break;
    }
    cJSON_AddStringToObject(json_root, "mode", mode_str);

    // Serialize and send
    char* json_string = cJSON_PrintUnformatted(json_root);
    if (json_string != nullptr) {
        SendText(std::string(json_string));
        cJSON_free(json_string);
    }

    // Clean up
    cJSON_Delete(json_root);
}

