void Protocol::SendStopListening()
{
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        ESP_LOGE(TAG, "Failed to create JSON object for StopListening");
        return;
    }

    cJSON_AddStringToObject(root, "type", "listen");
    cJSON_AddStringToObject(root, "state", "stop");
    cJSON_AddStringToObject(root, "sessionId", session_id_.c_str());

    char* json_str = cJSON_PrintUnformatted(root);
    if (json_str) {
        SendText(std::string(json_str));
        cJSON_free(json_str);
    } else {
        ESP_LOGE(TAG, "Failed to serialize JSON for StopListening");
    }

    cJSON_Delete(root);
}

