void Protocol::SendMcpMessage(const std::string& message)
{
    cJSON* json_root = cJSON_CreateObject();
    if (!json_root) {
        ESP_LOGE(TAG, "Failed to create JSON object");
        return;
    }

    // Add session ID
    cJSON_AddStringToObject(json_root, "sessionId", session_id_.c_str());

    // Add the message payload as a string (assuming it's already valid JSON or opaque data)
    cJSON_AddStringToObject(json_root, "payload", message.c_str());

    // Render JSON to string
    char* json_str = cJSON_PrintUnformatted(json_root);
    if (json_str) {
        SendText(std::string(json_str));
        cJSON_free(json_str); // cJSON internal allocator
    } else {
        ESP_LOGE(TAG, "Failed to print JSON string");
    }

    cJSON_Delete(json_root);
}

