bool Protocol::IsTimeout() const
{
    auto now = std::chrono::steady_clock::now();
    auto elapsed = std::chrono::duration_cast<std::chrono::seconds>(now - last_incoming_time_).count();

    if (elapsed >= 120) {
        ESP_LOGE(TAG, "Channel timeout: No incoming message for %lld seconds", static_cast<long long>(elapsed));
        return true;
    }

    return false;
}

