bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    // Check if WebSocket is connected and audio channel is opened
    if (!websocket_ || !IsAudioChannelOpened()) {
        ESP_LOGW(TAG, "WebSocket not connected or audio channel not opened");
        return false;
    }

    // Check if packet is valid
    if (!packet || packet->data.empty()) {
        ESP_LOGW(TAG, "Invalid audio packet");
        return false;
    }

    // Prepare buffer for the formatted packet
    std::vector<uint8_t> formatted_data;

    // Handle different protocol versions
    switch (version_) {
        case 2: {
            // Protocol v2: [timestamp][payload_size][audio_data]
            uint32_t timestamp = htonl(static_cast<uint32_t>(packet->timestamp));
            uint32_t payload_size = htonl(static_cast<uint32_t>(packet->data.size()));

            formatted_data.resize(sizeof(timestamp) + sizeof(payload_size) + packet->data.size());

            uint8_t* ptr = formatted_data.data();
            std::memcpy(ptr, &timestamp, sizeof(timestamp));
            ptr += sizeof(timestamp);
            std::memcpy(ptr, &payload_size, sizeof(payload_size));
            ptr += sizeof(payload_size);
            std::memcpy(ptr, packet->data.data(), packet->data.size());
            break;
        }

        case 3: {
            // Protocol v3: [header][timestamp][payload_size][audio_data]
            struct ProtocolV3Header {
                uint8_t magic[4] = {0x57, 0x53, 0x56, 0x33}; // "WSV3"
                uint32_t timestamp;
                uint32_t payload_size;
            } __attribute__((packed));

            ProtocolV3Header header;
            header.timestamp = htonl(static_cast<uint32_t>(packet->timestamp));
            header.payload_size = htonl(static_cast<uint32_t>(packet->data.size()));

            formatted_data.resize(sizeof(header) + packet->data.size());

            uint8_t* ptr = formatted_data.data();
            std::memcpy(ptr, &header, sizeof(header));
            ptr += sizeof(header);
            std::memcpy(ptr, packet->data.data(), packet->data.size());
            break;
        }

        default: {
            // Raw payload format (version 1 or unknown)
            formatted_data = std::move(packet->data);
            break;
        }
    }

    // Send the formatted data over WebSocket
    if (!websocket_->SendBinary(formatted_data.data(), formatted_data.size())) {
        ESP_LOGE(TAG, "Failed to send audio packet over WebSocket");
        return false;
    }

    return true;
}

