bool WebsocketProtocol::OpenAudioChannel()
{
    if (websocket_ && websocket_->IsConnected()) {
        ESP_LOGW(TAG, "Audio channel already opened");
        return true;
    }

    // Get system info for authentication
    SystemInfo system_info;
    std::string device_id = system_info.GetDeviceId();
    std::string auth_token = Application::GetInstance().GetAuthToken();

    // Construct WebSocket URL for audio streaming
    Settings& settings = Settings::GetInstance();
    std::string ws_url = settings.GetWebsocketUrl();
    if (ws_url.empty()) {
        ESP_LOGE(TAG, "WebSocket URL not configured");
        return false;
    }

    // Append audio channel endpoint
    if (ws_url.back() != '/') {
        ws_url += "/";
    }
    ws_url += "audio";

    // Create WebSocket instance
    try {
        websocket_ = std::make_unique<WebSocket>(ws_url);

        // Set authentication headers
        websocket_->SetHeader("Authorization", "Bearer " + auth_token);
        websocket_->SetHeader("X-Device-ID", device_id);
        websocket_->SetHeader("X-Protocol-Version", std::to_string(version_));

        // Set binary protocol version
        websocket_->SetHeader("X-Binary-Protocol", "v" + std::to_string(version_));

        // Set up data handler for incoming binary audio packets
        websocket_->SetBinaryDataHandler([this](const uint8_t* data, size_t length) {
            if (length == 0 || !data) {
                return;
            }

            if (version_ == 2) {
                // Handle BinaryProtocol2
                if (length < sizeof(BinaryProtocol2)) {
                    ESP_LOGE(TAG, "Invalid binary protocol v2 packet size: %d", length);
                    return;
                }

                const BinaryProtocol2* packet = reinterpret_cast<const BinaryProtocol2*>(data);
                uint32_t payload_size = ntohl(packet->payload_size);
                uint32_t timestamp = ntohl(packet->timestamp);

                if (sizeof(BinaryProtocol2) + payload_size > length) {
                    ESP_LOGE(TAG, "Binary protocol v2 packet truncated");
                    return;
                }

                // Create audio packet
                auto audio_packet = std::make_unique<AudioStreamPacket>();
                audio_packet->sample_rate = server_sample_rate_;
                audio_packet->frame_duration = server_frame_duration_;
                audio_packet->timestamp = timestamp;
                audio_packet->payload.assign(packet->payload, packet->payload + payload_size);

                // Notify listeners
                if (on_incoming_audio_) {
                    on_incoming_audio_(std::move(audio_packet));
                }
            }
            else if (version_ == 3) {
                // Handle BinaryProtocol3
                if (length < sizeof(BinaryProtocol3)) {
                    ESP_LOGE(TAG, "Invalid binary protocol v3 packet size: %d", length);
                    return;
                }

                const BinaryProtocol3* packet = reinterpret_cast<const BinaryProtocol3*>(data);
                uint16_t payload_size = ntohs(packet->payload_size);

                if (sizeof(BinaryProtocol3) + payload_size > length) {
                    ESP_LOGE(TAG, "Binary protocol v3 packet truncated");
                    return;
                }

                // Create audio packet
                auto audio_packet = std::make_unique<AudioStreamPacket>();
                audio_packet->sample_rate = server_sample_rate_;
                audio_packet->frame_duration = server_frame_duration_;
                audio_packet->timestamp = 0; // V3 doesn't include timestamp
                audio_packet->payload.assign(packet->payload, packet->payload + payload_size);

                // Notify listeners
                if (on_incoming_audio_) {
                    on_incoming_audio_(std::move(audio_packet));
                }
            }
            else {
                ESP_LOGE(TAG, "Unsupported binary protocol version: %d", version_);
            }
        });

        // Set up text message handler for control messages
        websocket_->SetTextDataHandler([this](const std::string& message) {
            cJSON* root = cJSON_Parse(message.c_str());
            if (root) {
                ParseServerHello(root);
                cJSON_Delete(root);
            }
        });

        // Set connection state handlers
        websocket_->SetConnectionHandler([this]() {
            ESP_LOGI(TAG, "Audio channel WebSocket connected");
            if (on_audio_channel_opened_) {
                on_audio_channel_opened_();
            }
        });

        websocket_->SetDisconnectionHandler([this]() {
            ESP_LOGI(TAG, "Audio channel WebSocket disconnected");
            if (on_audio_channel_closed_) {
                on_audio_channel_closed_();
            }
        });

        // Connect
        if (!websocket_->Connect()) {
            ESP_LOGE(TAG, "Failed to connect audio channel WebSocket");
            websocket_.reset();
            return false;
        }

        return true;
    }
    catch (const std::exception& e) {
        ESP_LOGE(TAG, "Exception while opening audio channel: %s", e.what());
        websocket_.reset();
        return false;
    }
}

