std::string WebsocketProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", version_);

    // Add transport type
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add supported features
    cJSON *features = cJSON_CreateObject();
    cJSON_AddBoolToObject(features, "aec", FEATURE_AEC_ENABLED);  // Assuming this macro or variable exists
    cJSON_AddBoolToObject(features, "mcp", true);                 // Placeholder; adjust if needed
    cJSON_AddItemToObject(root, "features", features);

    // Add audio configuration
    cJSON *audio = cJSON_CreateObject();
    cJSON_AddStringToObject(audio, "format", "pcm");              // Example format
    cJSON_AddNumberToObject(audio, "sample_rate", 16000);         // Common default
    cJSON_AddNumberToObject(audio, "channels", 1);                // Mono
    cJSON_AddNumberToObject(audio, "frame_duration", 20);         // In milliseconds
    cJSON_AddItemToObject(root, "audio", audio);

    // Print and clean up
    char *json_str = cJSON_PrintUnformatted(root);
    std::string result(json_str ? json_str : "");
    if (json_str) {
        free(json_str);
    }
    cJSON_Delete(root);

    return result;
}

