void WebsocketProtocol::ParseServerHello(const cJSON* root)
{
    if (root == nullptr) {
        ESP_LOGE(TAG, "Invalid JSON root in ParseServerHello");
        return;
        }

    // Parse session ID
    cJSON* session_id = cJSON_GetObjectItem(root, "sessionId");
    if (session_id != nullptr && cJSON_IsString(session_id)) {
        // In a real implementation, you would store this session ID
        ESP_LOGI(TAG, "Session ID: %s", session_id->valuestring);
    } else {
        ESP_LOGW(TAG, "Missing or invalid sessionId in server hello");
    }

    // Parse audio configuration
    cJSON* audio_config = cJSON_GetObjectItem(root, "audio");
    if (audio_config != nullptr && cJSON_IsObject(audio_config)) {
        // Parse sample rate
        cJSON* sample_rate = cJSON_GetObjectItem(audio_config, "sampleRate");
        if (sample_rate != nullptr && cJSON_IsNumber(sample_rate)) {
            int rate = sample_rate->valueint;
            ESP_LOGI(TAG, "Audio sample rate: %d Hz", rate);
            // In a real implementation, you would configure the audio system with this value
        }

        // Parse frame duration
        cJSON* frame_duration = cJSON_GetObjectItem(audio_config, "frameDuration");
        if (frame_duration != nullptr && cJSON_IsNumber(frame_duration)) {
            int duration = frame_duration->valueint;
            ESP_LOGI(TAG, "Audio frame duration: %d ms", duration);
            // In a real implementation, you would configure the audio system with this value
        }
    } else {
        ESP_LOGW(TAG, "Missing or invalid audio configuration in server hello");
    }

    // Validate transport type
    cJSON* transport = cJSON_GetObjectItem(root, "transport");
    if (transport != nullptr && cJSON_IsString(transport)) {
        if (strcmp(transport->valuestring, "websocket") != 0) {
            ESP_LOGW(TAG, "Unsupported transport type: %s", transport->valuestring);
        } else {
            ESP_LOGI(TAG, "Transport type validated: %s", transport->valuestring);
        }
    } else {
        ESP_LOGW(TAG, "Missing or invalid transport type in server hello");
    }

    // Set event flag to signal readiness for further communication
    xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);

    ESP_LOGI(TAG, "Server hello parsed successfully");
}
